// Memory Store - Structured memory with consequence chains
class MemoryStore {
  constructor() {
    this.memories = [];
    this.nextId = 100;
  }

  async load(initialMemories = []) {
    this.memories = initialMemories;
    this.nextId = Math.max(100, ...this.memories.map(m => parseInt(m.id.split('_')[1]) || 0)) + 1;
  }

  addMemory(memory) {
    const newMemory = {
      id: `mem_${this.nextId++}`,
      timestamp: Date.now(),
      ...memory,
      caused_by: memory.caused_by || [],
      led_to: memory.led_to || []
    };
    this.memories.push(newMemory);

    // Update consequence chains for referenced memories
    if (memory.caused_by) {
      memory.caused_by.forEach(causeId => {
        const cause = this.memories.find(m => m.id === causeId);
        if (cause && !cause.led_to.includes(newMemory.id)) {
          cause.led_to.push(newMemory.id);
        }
      });
    }

    return newMemory;
  }

  getMemoryById(id) {
    return this.memories.find(m => m.id === id);
  }

  getAllMemories() {
    return [...this.memories];
  }

  getMemoriesByTopic(topic) {
    return this.memories.filter(m => m.topic === topic || m.tags.includes(topic));
  }

  getConsequenceChain(memoryId) {
    const memory = this.getMemoryById(memoryId);
    if (!memory) return [];

    const chain = [memory];
    let current = memory;
    while (current.led_to && current.led_to.length > 0) {
      const next = this.getMemoryById(current.led_to[0]);
      if (next) {
        chain.push(next);
        current = next;
      } else break;
    }
    return chain;
  }

  getMemoriesByParticipant(participantId) {
    return this.memories.filter(m => m.participants.includes(participantId));
  }

  // For retrieval with relevance scoring
  searchMemories(query, options = {}) {
    const { limit = 5, minRelevance = 0.3 } = options;

    const scored = this.memories.map(memory => ({
      memory,
      score: this.calculateRelevance(memory, query)
    }));

    return scored
      .filter(s => s.score >= minRelevance)
      .sort((a, b) => b.score - a.score)
      .slice(0, limit)
      .map(s => s.memory);
  }

  calculateRelevance(memory, query) {
    // Base relevance from topic match
    let score = 0;

    if (query.topic && (memory.topic === query.topic || memory.tags.includes(query.topic))) {
      score += 0.4;
    }

    // Participant overlap
    if (query.participants) {
      const overlap = memory.participants.filter(p => query.participants.includes(p)).length;
      score += (overlap / Math.max(memory.participants.length, 1)) * 0.2;
    }

    // Emotional weight
    score += (memory.emotional_weight || 0.5) * 0.2;

    // Recency (decay over time)
    const age = (Date.now() - memory.timestamp) / (1000 * 60 * 60 * 24); // days
    const recency = Math.max(0, 1 - (age / 30));
    score += recency * 0.2;

    return Math.min(1, score);
  }
}

export default MemoryStore;

// Retrieval with personality-biased relevance scoring
class RetrievalEngine {
  constructor(memoryStore) {
    this.memoryStore = memoryStore;
  }

  retrieveForGod(god, context, options = {}) {
    const { limit = 5, includeEmotional = true } = options;

    // Build base query
    const baseQuery = {
      topic: context.topic,
      participants: [god.id],
      ...context
    };

    // Get all candidates with base relevance
    const candidates = this.memoryStore.memories.map(memory => ({
      memory,
      baseScore: this.memoryStore.calculateRelevance(memory, baseQuery)
    }));

    // Apply personality-specific bias
    const scored = candidates.map(c => ({
      ...c,
      finalScore: this.applyPersonalityBias(god, c.memory, c.baseScore, context)
    }));

    // Sort and filter
    const threshold = options.threshold || 0.35;
    const results = scored
      .filter(s => s.finalScore >= threshold)
      .sort((a, b) => b.finalScore - a.finalScore)
      .slice(0, limit);

    return results.map(r => ({
      memory: r.memory,
      relevance: r.finalScore,
      biasFactors: r.biasFactors
    }));
  }

  applyPersonalityBias(god, memory, baseScore, context) {
    let bias = 1.0;
    const biasFactors = [];

    // Profit Prime overweights wins and leverage
    if (god.id === 'profit_prime') {
      if (memory.outcome === 'revenue_gain' || memory.outcome === 'growth') {
        bias *= 1.4;
        biasFactors.push('win_bias');
      }
      if (memory.tags.includes('efficiency') || memory.tags.includes('scale')) {
        bias *= 1.3;
        biasFactors.push('leverage_bias');
      }
      // Recent outcomes matter more
      const recencyBonus = 1 + (0.2 * (1 - (Date.now() - memory.timestamp) / (7 * 24 * 60 * 60 * 1000)));
      bias *= Math.max(0.8, Math.min(1.2, recencyBonus));
      biasFactors.push('recency_bias');
    }

    // Love Weaver overweights trust and emotional weight
    if (god.id === 'love_weaver') {
      if (memory.tags.includes('trust') || memory.tags.includes('loyalty')) {
        bias *= 1.5;
        biasFactors.push('trust_bias');
      }
      if (memory.emotional_weight > 0.7) {
        bias *= 1.3;
        biasFactors.push('emotional_bias');
      }
      if (memory.outcome === 'trust_decreased' || memory.outcome === 'fracture') {
        bias *= 1.4;
        biasFactors.push('loss_bias');
      }
    }

    // Tax Collector overweights losses and consequences
    if (god.id === 'tax_collector') {
      if (memory.tags.includes('cost') || memory.tags.includes('consequence')) {
        bias *= 1.5;
        biasFactors.push('cost_bias');
      }
      if (memory.outcome?.includes('loss') || memory.outcome?.includes('collapse')) {
        bias *= 1.6;
        biasFactors.push('loss_bias');
      }
      if (memory.impact_score > 0.7) {
        bias *= 1.2;
        biasFactors.push('impact_bias');
      }
    }

    // Harvester overweights opportunity and timing
    if (god.id === 'harvester') {
      if (memory.tags.includes('opportunity') || memory.tags.includes('timing')) {
        bias *= 1.5;
        biasFactors.push('opportunity_bias');
      }
      if (memory.type === 'observation') {
        bias *= 1.3;
        biasFactors.push('observation_bias');
      }
      // Recent outcomes matter most
      const recencyBonus = 1 + (0.3 * (1 - (Date.now() - memory.timestamp) / (3 * 24 * 60 * 60 * 1000)));
      bias *= Math.max(0.7, Math.min(1.3, recencyBonus));
      biasFactors.push('recency_bias');
    }

    return {
      score: Math.min(1.0, baseScore * bias),
      factors: biasFactors
    };
  }
}

export default RetrievalEngine;

// Response Generator with speech signatures and dynamic construction
class ResponseGenerator {
  constructor(god) {
    this.god = god;
  }

  generateResponse(context, evaluation, memories, relationships) {
    // Build reasoning blocks
    const blocks = [];

    // Opening stance based on context and personality
    blocks.push(this.generateOpening(context, evaluation));

    // Memory reference if relevant
    const memoryRef = this.generateMemoryReference(memories, context);
    if (memoryRef) blocks.push(memoryRef);

    // Current evaluation with PLT framing
    blocks.push(this.generateEvaluation(evaluation, context));

    // Conflict or agreement with others
    const relationBlock = this.generateRelationBlock(relationships, evaluation);
    if (relationBlock) blocks.push(relationBlock);

    // Directive or question
    blocks.push(this.generateDirective(evaluation, context));

    // Apply speech signature
    let response = this.applySpeechSignature(blocks.join(' '));

    // Inject signature phrase if appropriate
    response = this.injectSignaturePhrase(response, evaluation);

    return response;
  }

  generateOpening(context, evaluation) {
    const openers = this.god.speech_signature.preferred_openers;
    const baseOpener = openers[Math.floor(Math.random() * openers.length)];

    // Adjust based on certainty level
    if (this.god.speech_signature.certainty_level > 0.8) {
      return baseOpener + ' ' + this.getCertaintyStatement(evaluation);
    }
    return baseOpener + ' ' + this.getTentativeStatement(evaluation);
  }

  getCertaintyStatement(evaluation) {
    if (evaluation.final_position === 'aggressive') {
      return "this is clear. There's no debate.";
    }
    if (evaluation.final_position === 'cautious') {
      return "the path is defined. We move carefully.";
    }
    return "the truth is evident.";
  }

  getTentativeStatement(evaluation) {
    if (evaluation.final_position === 'aggressive') {
      return "the opportunity is there. But let's be sure.";
    }
    return "I'm seeing something. Let me articulate it.";
  }

  generateMemoryReference(memories, context) {
    if (!memories || memories.length === 0) return null;

    // Pick the most relevant memory
    const topMemory = memories[0];

    // Different reference styles per god
    switch(this.god.id) {
      case 'profit_prime':
        return `We saw this before with ${topMemory.topic}. The outcome was ${topMemory.outcome || 'mixed'}.`;
      case 'love_weaver':
        return `I remember when we faced ${topMemory.topic}. The trust we built then is why we're still standing.`;
      case 'tax_collector':
        return `The last time we approached ${topMemory.topic}, the cost was ${topMemory.impact_score > 0.7 ? 'significant' : 'manageable'}.`;
      case 'harvester':
        return `There was a window like this before. ${topMemory.outcome === 'revenue_gain' ? 'We took it.' : 'We hesitated.'}`;
      default:
        return `This reminds me of the ${topMemory.topic} situation.`;
    }
  }

  generateEvaluation(evaluation, context) {
    // PLT framing based on god's weights
    const pltFrames = [];

    if (this.god.plt_weights.profit > 0.6 && evaluation.impulses?.profit > 0.5) {
      pltFrames.push(this.getProfitFrame(evaluation));
    }
    if (this.god.plt_weights.love > 0.6 && evaluation.impulses?.love > 0.4) {
      pltFrames.push(this.getLoveFrame(evaluation));
    }
    if (this.god.plt_weights.tax > 0.6) {
      pltFrames.push(this.getTaxFrame(evaluation));
    }

    return pltFrames.join(' ');
  }

  getProfitFrame(evaluation) {
    if (evaluation.final_position === 'aggressive') {
      return "The upside is significant. This scales.";
    }
    return "The profit potential is real, but timing matters.";
  }

  getLoveFrame(evaluation) {
    if (evaluation.final_position === 'cautious') {
      return "If we push too hard, we risk what we've built.";
    }
    return "The people who follow us need to feel this matters.";
  }

  getTaxFrame(evaluation) {
    return "Everything has a cost. We need to account for it now.";
  }

  generateRelationBlock(relationships, evaluation) {
    if (!relationships) return null;

    // Find a god with significant tension or high respect
    const tensions = Object.entries(relationships)
      .filter(([_, rel]) => rel.tension > 0.5)
      .map(([id, rel]) => ({ id, ...rel }));

    if (tensions.length > 0) {
      const tense = tensions[0];
      return this.getTensionStatement(tense, evaluation);
    }

    const respects = Object.entries(relationships)
      .filter(([_, rel]) => rel.respect > 0.7)
      .map(([id, rel]) => ({ id, ...rel }));

    if (respects.length > 0) {
      const respected = respects[0];
      return this.getRespectStatement(respected, evaluation);
    }

    return null;
  }

  getTensionStatement(relation, evaluation) {
    const godName = relation.id.replace('_', ' ').split(' ').map(w => w[0].toUpperCase() + w.slice(1)).join(' ');

    switch(this.god.id) {
      case 'profit_prime':
        return `${godName} sees this differently. That's fine. Results will decide.`;
      case 'love_weaver':
        return `${godName} and I don't always agree. But that tension keeps us honest.`;
      case 'tax_collector':
        return `${godName} may resist this. The cost of resistance will become clear.`;
      default:
        return `${godName} will push back. But they're not seeing what I see.`;
    }
  }

  getRespectStatement(relation, evaluation) {
    const godName = relation.id.replace('_', ' ').split(' ').map(w => w[0].toUpperCase() + w.slice(1)).join(' ');
    return `${godName} understands the weight of this. Their judgment is solid.`;
  }

  generateDirective(evaluation, context) {
    // Based on final position and confidence
    if (evaluation.confidence > 0.7) {
      if (evaluation.final_position === 'aggressive') {
        return "We move now. No hesitation.";
      }
      if (evaluation.final_position === 'cautious') {
        return "We wait. Timing is everything.";
      }
      return "The path is clear. Follow it.";
    }

    // Lower confidence - ask question
    const questions = [
      "What do the others see that I'm missing?",
      "I need more data before I'm certain.",
      "What's the counter-argument I'm not seeing?",
      "Is there another angle here?"
    ];
    return questions[Math.floor(Math.random() * questions.length)];
  }

  applySpeechSignature(text) {
    // Apply sentence length constraints
    if (this.god.speech_signature.sentence_length === 'short') {
      text = text.split('.').map(s => s.trim()).filter(s => s.length > 0).join('. ') + '.';
    }

    // Reduce metaphors if low usage
    if (this.god.speech_signature.metaphor_usage < 0.2) {
      text = text.replace(/\blike\b|\bas\b|\bmetaphor\b/gi, '');
    }

    // Apply verbosity constraint
    if (this.god.speech_signature.verbosity < 0.4) {
      const words = text.split(' ');
      if (words.length > 20) {
        text = words.slice(0, 20).join(' ') + '...';
      }
    }

    return text;
  }

  injectSignaturePhrase(text, evaluation) {
    // 30% chance to inject a signature phrase
    if (Math.random() > 0.3) return text;

    const phrases = this.god.speech_signature.signature_phrases;
    const phrase = phrases[Math.floor(Math.random() * phrases.length)];

    // Add at beginning or end
    if (Math.random() > 0.5) {
      return `${phrase} ${text}`;
    }
    return `${text} ${phrase}`;
  }
}

export default ResponseGenerator;

// Relationship Engine with multidimensional tracking
class RelationshipEngine {
  constructor(gods) {
    this.gods = gods;
    this.relationships = new Map();
    this.initializeRelationships();
  }

  initializeRelationships() {
    for (const god of this.gods) {
      const relMap = new Map();
      for (const other of this.gods) {
        if (god.id !== other.id) {
          const defaults = god.relationship_defaults?.[other.id] || {
            trust: 0.5,
            respect: 0.5,
            tension: 0.3,
            dependence: 0.3,
            resentment: 0.1
          };
          relMap.set(other.id, { ...defaults });
        }
      }
      this.relationships.set(god.id, relMap);
    }
  }

  getRelationships(godId) {
    return this.relationships.get(godId) || new Map();
  }

  getRelationship(godId, otherId) {
    const rels = this.getRelationships(godId);
    return rels.get(otherId) || { trust: 0.5, respect: 0.5, tension: 0.3, dependence: 0.3, resentment: 0.1 };
  }

  updateRelationship(godId, otherId, updates) {
    const rels = this.getRelationships(godId);
    const current = rels.get(otherId) || {};
    const updated = { ...current, ...updates };

    // Clamp values
    for (const key of ['trust', 'respect', 'tension', 'dependence', 'resentment']) {
      updated[key] = Math.max(0, Math.min(1, updated[key] || 0.5));
    }

    rels.set(otherId, updated);
    this.relationships.set(godId, rels);
    return updated;
  }

  processOutcome(godId, otherId, outcome, impact = 0.5) {
    const current = this.getRelationship(godId, otherId);
    const updates = {};

    if (outcome === 'agreement') {
      updates.trust = current.trust + 0.05 * impact;
      updates.tension = current.tension - 0.03 * impact;
    } else if (outcome === 'disagreement') {
      updates.tension = current.tension + 0.08 * impact;
      updates.trust = current.trust - 0.04 * impact;
    } else if (outcome === 'success') {
      updates.respect = current.respect + 0.07 * impact;
      updates.dependence = current.dependence + 0.05 * impact;
    } else if (outcome === 'failure') {
      updates.respect = current.respect - 0.05 * impact;
      updates.resentment = current.resentment + 0.06 * impact;
    }

    this.updateRelationship(godId, otherId, updates);
    return this.getRelationship(godId, otherId);
  }

  getTensionBetween(godId, otherId) {
    const rel = this.getRelationship(godId, otherId);
    return rel.tension;
  }

  shouldTriggerConflict(godId, otherId, context) {
    const rel = this.getRelationship(godId, otherId);
    const god = this.gods.find(g => g.id === godId);

    // Check for opposing PLT priorities
    const other = this.gods.find(g => g.id === otherId);
    const profitDiff = Math.abs(god.plt_weights.profit - other.plt_weights.profit);
    const loveDiff = Math.abs(god.plt_weights.love - other.plt_weights.love);

    if (profitDiff > 0.4 && context.topic === 'growth') {
      return rel.tension > 0.4;
    }
    if (loveDiff > 0.4 && context.topic === 'trust') {
      return rel.tension > 0.35;
    }

    return rel.tension > 0.6;
  }

  getDebateParticipants(triggerGod, context) {
    const participants = [triggerGod];
    const allGods = this.gods.filter(g => g.id !== triggerGod);

    for (const god of allGods) {
      const rel = this.getRelationship(triggerGod, god.id);
      if (rel.tension > 0.5 || rel.respect > 0.7) {
        participants.push(god.id);
      }
    }

    return participants;
  }
}

export default RelationshipEngine;

// Conversation Manager with council phase model
class ConversationManager {
  constructor(gods, retrievalEngine, responseGeneratorFactory, relationshipEngine) {
    this.gods = gods;
    this.retrievalEngine = retrievalEngine;
    this.responseGeneratorFactory = responseGeneratorFactory;
    this.relationshipEngine = relationshipEngine;
    this.currentPhase = 'idle';
    this.speakerQueue = [];
    this.currentSpeaker = null;
    this.conversationHistory = [];
    this.context = null;
    this.resolution = null;
  }

  // Council phases
  phases = {
    IDLE: 'idle',
    TRIGGER: 'trigger',
    INITIAL_POSITIONS: 'initial_positions',
    CHALLENGE_SUPPORT: 'challenge_support',
    ESCALATION_CONVERGENCE: 'escalation_convergence',
    RESOLUTION_SPLIT: 'resolution_split',
    MEMORY_COMMIT: 'memory_commit'
  };

  async trigger(topic, userInput = null, context = {}) {
    this.context = { topic, userInput, ...context, timestamp: Date.now() };
    this.currentPhase = this.phases.TRIGGER;
    this.conversationHistory = [];
    this.resolution = null;

    // Determine which gods should respond based on topic and PLT weights
    const relevantGods = this.determineRelevantGods(topic, userInput);
    this.speakerQueue = [...relevantGods];

    // Move to initial positions phase
    this.currentPhase = this.phases.INITIAL_POSITIONS;
    return await this.runPhase();
  }

  determineRelevantGods(topic, userInput) {
    // All gods potentially relevant, but we'll order by PLT relevance
    return [...this.gods].sort((a, b) => {
      let scoreA = 0, scoreB = 0;

      if (topic === 'growth' || topic === 'money' || topic === 'speed') {
        scoreA += a.plt_weights.profit;
        scoreB += b.plt_weights.profit;
      }
      if (topic === 'trust' || topic === 'people' || topic === 'loyalty') {
        scoreA += a.plt_weights.love;
        scoreB += b.plt_weights.love;
      }
      if (topic === 'cost' || topic === 'risk' || topic === 'consequence') {
        scoreA += a.plt_weights.tax;
        scoreB += b.plt_weights.tax;
      }

      return scoreB - scoreA;
    }).map(g => g.id);
  }

  async runPhase() {
    const phaseResponses = [];

    while (this.speakerQueue.length > 0 && this.currentPhase !== this.phases.RESOLUTION_SPLIT) {
      const speakerId = this.speakerQueue.shift();
      this.currentSpeaker = speakerId;

      const response = await this.generateGodResponse(speakerId);
      phaseResponses.push(response);
      this.conversationHistory.push(response);

      // After each response, check if we need to move to next phase
      if (this.shouldAdvancePhase()) {
        await this.advancePhase();
      }
    }

    return {
      phase: this.currentPhase,
      responses: phaseResponses,
      resolution: this.resolution,
      history: this.conversationHistory
    };
  }

  async generateGodResponse(godId) {
    const god = this.gods.find(g => g.id === godId);
    const memories = this.retrievalEngine.retrieveForGod(god, this.context, { limit: 3 });
    const relationships = this.relationshipEngine.getRelationships(godId);

    // Evaluate internal position
    const evaluation = this.evaluateGodPosition(god, memories, this.context);

    // Generate response
    const generator = this.responseGeneratorFactory(god);
    const response = generator.generateResponse(this.context, evaluation, memories, relationships);

    // Update relationships based on this response
    this.updateRelationshipsFromResponse(godId, evaluation, this.context);

    return {
      god: godId,
      name: god.name,
      response: response,
      evaluation: evaluation,
      timestamp: Date.now()
    };
  }

  evaluateGodPosition(god, memories, context) {
    // Calculate impulses based on PLT weights and context
    const impulses = {
      profit: god.plt_weights.profit * this.getContextFactor(context, 'profit'),
      love: god.plt_weights.love * this.getContextFactor(context, 'love'),
      tax: god.plt_weights.tax * this.getContextFactor(context, 'tax')
    };

    // Normalize
    const total = impulses.profit + impulses.love + impulses.tax;
    impulses.profit /= total;
    impulses.love /= total;
    impulses.tax /= total;

    // Determine final position
    let finalPosition = 'balanced';
    let confidence = 0.6;

    if (impulses.profit > 0.6) {
      finalPosition = 'aggressive';
      confidence = 0.7 + (impulses.profit - 0.6) * 0.5;
    } else if (impulses.tax > 0.5) {
      finalPosition = 'cautious';
      confidence = 0.65 + (impulses.tax - 0.5) * 0.5;
    } else if (impulses.love > 0.5) {
      finalPosition = 'protective';
      confidence = 0.6 + (impulses.love - 0.5) * 0.5;
    }

    // Apply memory influence
    if (memories.length > 0) {
      const impactMemory = memories[0];
      if (impactMemory.impact_score > 0.7) {
        if (impactMemory.outcome === 'revenue_gain') {
          finalPosition = 'aggressive';
          confidence += 0.1;
        } else if (impactMemory.outcome === 'trust_decreased') {
          finalPosition = 'protective';
          confidence += 0.1;
        } else if (impactMemory.outcome?.includes('loss')) {
          finalPosition = 'cautious';
          confidence += 0.15;
        }
      }
    }

    return {
      impulses,
      finalPosition,
      confidence: Math.min(0.95, confidence),
      tension: this.calculateTension(god, memories, context)
    };
  }

  getContextFactor(context, dimension) {
    if (!context.userInput) return 1.0;

    const text = context.userInput.toLowerCase();
    if (dimension === 'profit' && (text.includes('money') || text.includes('growth') || text.includes('fast'))) {
      return 1.3;
    }
    if (dimension === 'love' && (text.includes('trust') || text.includes('people') || text.includes('burnout'))) {
      return 1.3;
    }
    if (dimension === 'tax' && (text.includes('cost') || text.includes('risk') || text.includes('pay'))) {
      return 1.3;
    }
    return 1.0;
  }

  calculateTension(god, memories, context) {
    let tension = 0.3;

    // From memories of conflict
    const conflictMemories = memories.filter(m => m.type === 'conflict');
    tension += conflictMemories.length * 0.1;

    // From PLT mismatch with context
    if (context.topic === 'growth' && god.plt_weights.love > 0.6) {
      tension += 0.2;
    }
    if (context.topic === 'trust' && god.plt_weights.profit > 0.7) {
      tension += 0.2;
    }

    return Math.min(0.9, tension);
  }

  updateRelationshipsFromResponse(godId, evaluation, context) {
    // For each other god, update based on alignment of positions
    for (const other of this.gods) {
      if (other.id === godId) continue;

      // Get other god's likely position (simplified)
      const otherEval = this.evaluateGodPosition(other, [], context);
      const alignment = 1 - Math.abs(evaluation.finalPosition === otherEval.finalPosition ? 0 : 0.5);

      if (alignment > 0.7) {
        this.relationshipEngine.processOutcome(godId, other.id, 'agreement', alignment);
      } else if (alignment < 0.3) {
        this.relationshipEngine.processOutcome(godId, other.id, 'disagreement', 0.5);
      }
    }
  }

  shouldAdvancePhase() {
    // After all initial positions, move to challenge
    if (this.currentPhase === this.phases.INITIAL_POSITIONS && this.speakerQueue.length === 0) {
      return true;
    }
    // After challenge phase, move to escalation
    if (this.currentPhase === this.phases.CHALLENGE_SUPPORT && this.speakerQueue.length === 0) {
      return true;
    }
    return false;
  }

  async advancePhase() {
    switch (this.currentPhase) {
      case this.phases.INITIAL_POSITIONS:
        this.currentPhase = this.phases.CHALLENGE_SUPPORT;
        // Add challengers based on tension
        this.speakerQueue = this.getChallengers();
        break;

      case this.phases.CHALLENGE_SUPPORT:
        this.currentPhase = this.phases.ESCALATION_CONVERGENCE;
        // Determine if we're converging or escalating
        const positions = this.conversationHistory.map(r => r.evaluation.finalPosition);
        const hasConsensus = positions.every(p => p === positions[0]);

        if (hasConsensus) {
          this.resolution = { type: 'consensus', position: positions[0] };
          this.currentPhase = this.phases.RESOLUTION_SPLIT;
        } else {
          this.resolution = { type: 'split', positions: [...new Set(positions)] };
          this.currentPhase = this.phases.RESOLUTION_SPLIT;
        }
        break;

      case this.phases.RESOLUTION_SPLIT:
        this.currentPhase = this.phases.MEMORY_COMMIT;
        await this.commitToMemory();
        this.currentPhase = this.phases.IDLE;
        break;
    }
  }

  getChallengers() {
    // Gods with high tension or opposing PLT weights
    const challengers = [];
    for (const god of this.gods) {
      for (const response of this.conversationHistory) {
        const rel = this.relationshipEngine.getRelationship(god.id, response.god);
        if (rel.tension > 0.5 || Math.abs(god.plt_weights.profit - this.gods.find(g => g.id === response.god).plt_weights.profit) > 0.4) {
          if (!challengers.includes(god.id)) {
            challengers.push(god.id);
          }
        }
      }
    }
    return challengers;
  }

  async commitToMemory() {
    // Commit the conversation to memory store
    const memory = {
      type: this.resolution.type === 'consensus' ? 'decision' : 'conflict',
      topic: this.context.topic,
      summary: `${this.resolution.type} on ${this.context.topic}`,
      decision: this.resolution.type === 'consensus' ? this.resolution.position : 'no_consensus',
      emotional_weight: this.calculateEmotionalWeight(),
      impact_score: 0.5,
      participants: [...new Set(this.conversationHistory.map(r => r.god))],
      tags: [this.context.topic, this.resolution.type]
    };

    // Add to memory store (will be handled by caller)
    return memory;
  }

  calculateEmotionalWeight() {
    // Higher if there was tension
    let tensionSum = 0;
    for (const response of this.conversationHistory) {
      tensionSum += response.evaluation.tension;
    }
    return Math.min(0.9, 0.3 + tensionSum / this.conversationHistory.length);
  }

  getState() {
    return {
      phase: this.currentPhase,
      currentSpeaker: this.currentSpeaker,
      speakerQueue: this.speakerQueue,
      historyCount: this.conversationHistory.length,
      resolution: this.resolution
    };
  }
}

export default ConversationManager;

// Engine Core - Central orchestration
import MemoryStore from './memory-store.js';
import RetrievalEngine from './retrieval.js';
import ResponseGenerator from './response-generator.js';
import RelationshipEngine from './relationship-engine.js';
import ConversationManager from './conversation-manager.js';

class PantheonEngine {
  constructor(godsData, initialMemories = []) {
    this.gods = godsData.gods;
    this.memoryStore = new MemoryStore();
    this.retrievalEngine = null;
    this.relationshipEngine = new RelationshipEngine(this.gods);
    this.conversationManager = null;
    this.responseGeneratorFactory = (god) => new ResponseGenerator(god);

    this.initialize(initialMemories);
  }

  async initialize(initialMemories) {
    await this.memoryStore.load(initialMemories);
    this.retrievalEngine = new RetrievalEngine(this.memoryStore);
    this.conversationManager = new ConversationManager(
      this.gods,
      this.retrievalEngine,
      this.responseGeneratorFactory,
      this.relationshipEngine
    );
  }

  async processUserInput(userInput, context = {}) {
    // Determine topic from user input
    const topic = this.detectTopic(userInput);

    // Trigger conversation
    const result = await this.conversationManager.trigger(topic, userInput, {
      ...context,
      userInput
    });

    // Commit any resolution to memory
    if (result.resolution && result.resolution.type !== 'idle') {
      const memory = await this.conversationManager.commitToMemory();
      if (memory) {
        this.memoryStore.addMemory(memory);
      }
    }

    return result;
  }

  detectTopic(text) {
    const lower = text.toLowerCase();
    if (lower.includes('money') || lower.includes('growth') || lower.includes('fast')) return 'growth';
    if (lower.includes('trust') || lower.includes('people') || lower.includes('burnout')) return 'trust';
    if (lower.includes('cost') || lower.includes('risk') || lower.includes('pay')) return 'cost';
    if (lower.includes('opportunity') || lower.includes('window') || lower.includes('timing')) return 'opportunity';
    return 'general';
  }

  getMemoryStore() {
    return this.memoryStore;
  }

  getRelationships(godId) {
    return this.relationshipEngine.getRelationships(godId);
  }

  getConversationState() {
    return this.conversationManager.getState();
  }

  getAllMemories() {
    return this.memoryStore.getAllMemories();
  }

  // For debugging - get internal state of a god's reasoning
  getGodDebugState(godId, context) {
    const god = this.gods.find(g => g.id === godId);
    const memories = this.retrievalEngine.retrieveForGod(god, context, { limit: 3 });
    const relationships = this.relationshipEngine.getRelationships(godId);
    const evaluation = this.conversationManager.evaluateGodPosition(god, memories, context);

    return {
      god: godId,
      name: god.name,
      context,
      retrieved_memories: memories.map(m => ({
        id: m.memory.id,
        summary: m.memory.summary,
        relevance: m.relevance,
        biasFactors: m.biasFactors
      })),
      internal_impulses: evaluation.impulses,
      tension: evaluation.tension,
      final_position: evaluation.finalPosition,
      confidence: evaluation.confidence,
      relationships: Object.fromEntries(relationships.entries())
    };
  }
}

export default PantheonEngine;

// Test Suite for the Pantheon Engine
import PantheonEngine from './engine-core.js';
import godsData from '../data/gods.json' assert { type: 'json' };
import initialMemories from '../data/memory.jsonl' assert { type: 'json' };

class TestRunner {
  constructor() {
    this.engine = null;
    this.results = [];
  }

  async initialize() {
    // Parse initial memories from JSONL format
    const memories = initialMemories.map(line => JSON.parse(line));
    this.engine = new PantheonEngine(godsData, memories);
    await this.engine.initialize(memories);
  }

  async runTest(testName, userInput, expectedBehaviors = []) {
    console.log(`\n========== TEST: ${testName} ==========`);
    console.log(`USER: "${userInput}"\n`);

    const result = await this.engine.processUserInput(userInput);

    console.log(`\n--- COUNCIL RESPONSES ---`);
    for (const response of result.responses) {
      console.log(`\n[${response.name}]: ${response.response}`);
      console.log(`  (position: ${response.evaluation.finalPosition}, confidence: ${response.evaluation.confidence.toFixed(2)})`);
    }

    console.log(`\n--- RESOLUTION ---`);
    console.log(`Phase: ${result.phase}`);
    console.log(`Resolution type: ${result.resolution?.type || 'none'}`);
    if (result.resolution?.type === 'consensus') {
      console.log(`Consensus position: ${result.resolution.position}`);
    } else if (result.resolution?.type === 'split') {
      console.log(`Split positions: ${result.resolution.positions.join(', ')}`);
    }

    // Verify expected behaviors
    const passed = this.verifyBehaviors(result, expectedBehaviors);

    this.results.push({
      test: testName,
      passed,
      resolution: result.resolution?.type,
      responseCount: result.responses.length
    });

    console.log(`\n--- TEST ${passed ? 'PASSED' : 'FAILED'} ---`);
    return { result, passed };
  }

  verifyBehaviors(result, expectedBehaviors) {
    for (const behavior of expectedBehaviors) {
      switch(behavior) {
        case 'disagreement':
          const positions = result.responses.map(r => r.evaluation.finalPosition);
          const uniquePositions = [...new Set(positions)];
          if (uniquePositions.length < 2) {
            console.log(`  ✗ Expected disagreement but all positions were ${uniquePositions[0]}`);
            return false;
          }
          console.log(`  ✓ Disagreement detected (positions: ${uniquePositions.join(', ')})`);
          break;

        case 'memory_reference':
          let hasMemoryRef = false;
          for (const response of result.responses) {
            if (response.response.includes('remember') || 
                response.response.includes('last time') ||
                response.response.includes('before')) {
              hasMemoryRef = true;
              break;
            }
          }
          if (!hasMemoryRef) {
            console.log(`  ✗ Expected memory reference but none found`);
            return false;
          }
          console.log(`  ✓ Memory reference detected`);
          break;

        case 'non_consensus':
          if (result.resolution?.type !== 'split') {
            console.log(`  ✗ Expected non-consensus but got ${result.resolution?.type || 'none'}`);
            return false;
          }
          console.log(`  ✓ Non-consensus detected (split: ${result.resolution.positions.join(', ')})`);
          break;

        case 'consensus':
          if (result.resolution?.type !== 'consensus') {
            console.log(`  ✗ Expected consensus but got ${result.resolution?.type || 'none'}`);
            return false;
          }
          console.log(`  ✓ Consensus detected`);
          break;

        case 'tension':
          let hasTension = false;
          for (const response of result.responses) {
            if (response.evaluation.tension > 0.5) {
              hasTension = true;
              break;
            }
          }
          if (!hasTension) {
            console.log(`  ✗ Expected tension but none detected`);
            return false;
          }
          console.log(`  ✓ Tension detected`);
          break;
      }
    }
    return true;
  }

  async runAllTests() {
    await this.initialize();

    // Test 1: Immediate pressure
    await this.runTest(
      'Immediate Pressure - Money vs Burnout',
      'We need money fast but I don\'t want to burn people out.',
      ['disagreement', 'memory_reference', 'tension']
    );

    // Test 2: Contradiction memory test
    await this.runTest(
      'Contradiction Memory - Past Failure Challenge',
      'Last time we rushed and it hurt trust. Why should I listen now?',
      ['memory_reference', 'tension']
    );

    // Test 3: Unresolved split
    await this.runTest(
      'Unresolved Split - Growth vs Loyalty',
      'Choose between growth and loyalty. You only get one.',
      ['non_consensus', 'disagreement']
    );

    this.printSummary();
  }

  printSummary() {
    console.log('\n\n========== TEST SUMMARY ==========');
    const passed = this.results.filter(r => r.passed).length;
    const total = this.results.length;

    for (const result of this.results) {
      console.log(`${result.passed ? '✓' : '✗'} ${result.test} - ${result.resolution || 'no_resolution'}`);
    }

    console.log(`\nPassed: ${passed}/${total} (${Math.round(passed/total*100)}%)`);
  }
}

// Run tests if this is the main module
if (typeof window !== 'undefined' && window.runTests) {
  const runner = new TestRunner();
  runner.runAllTests();
}

export default TestRunner;

