    <script type="module">
        import TestRunner from './js/tests.js';

        const outputDiv = document.getElementById('output');

        function log(message, isError = false) {
            const color = isError ? '#ff8888' : '#aaffaa';
            outputDiv.innerHTML += `<div style="color: ${color}">${message}</div>`;
            outputDiv.scrollTop = outputDiv.scrollHeight;
        }

        function clearOutput() {
            outputDiv.innerHTML = '<span style="color: #888;">Output cleared.</span>';
        }

        // Capture console logs to output
        const originalLog = console.log;
        const originalError = console.error;

        console.log = function(...args) {
            originalLog.apply(console, args);
            log(args.join(' '));
        };

        console.error = function(...args) {
            originalError.apply(console, args);
            log(args.join(' '), true);
        };

        async function runTest(testName, input, expectedBehaviors) {
            clearOutput();
            log(`🏁 Running: ${testName}`);
            log(`📝 Input: "${input}"`);
            log('');

            try {
                const runner = new TestRunner();
                await runner.initialize();
                const result = await runner.runTest(testName, input, expectedBehaviors);

                log('');
                log(`✅ ${result.passed ? 'PASSED' : 'FAILED'} - ${testName}`);

                if (result.result.resolution) {
                    log(`📊 Resolution: ${result.result.resolution.type}`);
                }
            } catch (error) {
                log(`❌ ERROR: ${error.message}`, true);
                console.error(error);
            }
