{"id":"mem_002","timestamp":1710003600,"type":"conflict","speaker":"love_weaver","topic":"trust_fracture","summary":"Rapid expansion caused trust erosion with early adopters","decision":"slowed_output","emotional_weight":0.89,"impact_score":0.73,"participants":["profit_prime","love_weaver","tax_collector"],"tags":["trust","burnout","consequence"],"parent_id":"mem_001","caused_by":["mem_001"],"led_to":["mem_003"],"outcome":"trust_decreased"}
{"id":"mem_003","timestamp":1710007200,"type":"decision","speaker":"tax_collector","topic":"stabilization","summary":"Implemented consolidation phase to rebuild trust","decision":"reduced_output_rate","emotional_weight":0.65,"impact_score":0.78,"participants":["profit_prime","love_weaver","tax_collector"],"tags":["stability","recovery","cost"],"parent_id":"mem_002","caused_by":["mem_002"],"led_to":[],"outcome":"stability_restored"}`;

        const initialMemories = memoryLines.split('\n').filter(l => l.trim()).map(l => JSON.parse(l));

        let engine = null;

        async function initEngine() {
            engine = new PantheonEngine(godsData, initialMemories);
            await engine.initialize(initialMemories);
            updateMemoryView();
            addChatMessage('system', '🧠 Pantheon Engine initialized. Four gods stand ready.');
        }

        function addChatMessage(speaker, message, evaluation = null) {
            const chatLog = document.getElementById('chatLog');
            const div = document.createElement('div');
            div.className = `message ${speaker === 'user' ? 'user' : speaker}`;

            let displayName = speaker;
            if (speaker === 'profit_prime') displayName = '💰 Profit Prime';
            else if (speaker === 'love_weaver') displayName = '❤️ Love Weaver';
            else if (speaker === 'tax_collector') displayName = '🧾 Tax Collector';
            else if (speaker === 'harvester') displayName = '🦅 Harvester';
            else if (speaker === 'system') displayName = '🏛️ System';
            else if (speaker === 'user') displayName = '👑 You';

            let html = `<strong>${displayName}:</strong> ${message}`;
            if (evaluation && speaker !== 'user') {
                html += `<br><span style="font-size: 9px; color: #888;">→ position: ${evaluation.finalPosition} | confidence: ${(evaluation.confidence * 100).toFixed(0)}% | tension: ${evaluation.tension.toFixed(2)}</span>`;
            }
            div.innerHTML = html;
            chatLog.appendChild(div);
            chatLog.scrollTop = chatLog.scrollHeight;

            // Update council state
            updateCouncilState();
        }

        async function updateCouncilState() {
            if (!engine) return;
            const state = engine.getConversationState();
            const div = document.getElementById('councilState');
            div.innerHTML = `
                <div>Phase: <strong>${state.phase}</strong></div>
                <div>Current Speaker: ${state.currentSpeaker || 'none'}</div>
                <div>Queue: ${state.speakerQueue?.length || 0} gods waiting</div>
                <div>Conversation Turns: ${state.historyCount}</div>
                <div>Resolution: ${state.resolution?.type || 'pending'}</div>
                ${state.resolution?.type === 'split' ? `<div class="status-badge split">SPLIT: ${state.resolution.positions?.join(' vs ')}</div>` : ''}
                ${state.resolution?.type === 'consensus' ? `<div class="status-badge active">CONSENSUS: ${state.resolution.position}</div>` : ''}
            `;
        }

        function updateMemoryView() {
            if (!engine) return;
            const memories = engine.getAllMemories();
            const div = document.getElementById('memoryView');
            div.innerHTML = memories.slice(-5).reverse().map(m => `
                <div style="border-bottom: 1px solid #222; padding: 5px 0;">
