        <div class="log-entry">🏛️ The expanded council awaits. Choose your tier.</div>
    </div>

    <div class="status" id="status">🟢 Council listening</div>

    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.128.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.128.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
        import { EffectComposer } from 'three/addons/postprocessing/EffectComposer.js';
        import { RenderPass } from 'three/addons/postprocessing/RenderPass.js';
        import { UnrealBloomPass } from 'three/addons/postprocessing/UnrealBloomPass.js';

        // ============================================================
        // PANTHEON v2 — Tiered Access, Credits, Commerce
        // ============================================================

        // --- USER STATE ---
        let userTier = 'free'; // free, premium, executive
        let credits = 0;
        let questionsUsedToday = 0;
        let lastResetDate = new Date().toDateString();
        let totalRevenue = 0;

        // Load from localStorage
        function loadUserState() {
            const saved = localStorage.getItem('pantheon_user');
            if (saved) {
                const data = JSON.parse(saved);
                userTier = data.userTier || 'free';
                credits = data.credits || 0;
                questionsUsedToday = data.questionsUsedToday || 0;
                lastResetDate = data.lastResetDate || new Date().toDateString();
                totalRevenue = data.totalRevenue || 0;
            }

            // Daily reset
            const today = new Date().toDateString();
            if (lastResetDate !== today) {
                questionsUsedToday = 0;
                lastResetDate = today;
                saveUserState();
            }

            updateUI();
        }

        function saveUserState() {
            localStorage.setItem('pantheon_user', JSON.stringify({
                userTier,
                credits,
                questionsUsedToday,
                lastResetDate,
                totalRevenue
            }));
        }

        function updateUI() {
            document.getElementById('creditCount').innerText = credits;
            document.getElementById('vaultDisplay').innerHTML = `$${totalRevenue.toFixed(2)}`;

            // Update active tier button
            document.querySelectorAll('.tier-btn').forEach(btn => {
                if (btn.dataset.tier === userTier) btn.classList.add('active');
                else btn.classList.remove('active');
            });

            // Show warning if out of questions
            const warning = document.getElementById('creditWarning');
            if (userTier === 'free' && questionsUsedToday >= 1) {
                warning.innerHTML = '⚠️ Free tier: 1 question per day. Upgrade or buy credits.';
            } else if (userTier === 'premium' && credits <= 0) {
                warning.innerHTML = '⚠️ No credits left. Buy more or upgrade to Executive.';
            } else {
                warning.innerHTML = '';
            }
        }

        function canAskQuestion() {
            if (userTier === 'executive') return true;
            if (userTier === 'premium') return credits > 0;
            if (userTier === 'free') return questionsUsedToday < 1;
            return false;
        }

        function consumeQuestion() {
            if (userTier === 'executive') return true;
            if (userTier === 'premium') {
                credits--;
                saveUserState();
                updateUI();
                return true;
            }
            if (userTier === 'free') {
                questionsUsedToday++;
                saveUserState();
                updateUI();
                return true;
            }
            return false;
        }

        function addRevenue(amount) {
            totalRevenue += amount;
            saveUserState();
            updateUI();
            addLogEntry('System', `💰 Revenue: +$${amount}. Total: $${totalRevenue.toFixed(2)}`, false);
        }

        // --- STRIPE INTEGRATION (simulated for demo) ---
        async function buyCredits() {
            addLogEntry('System', '🛒 Purchase 5 credits for $47. (Demo: adding credits)', false);
            credits += 5;
            addRevenue(47);
            saveUserState();
            updateUI();
            addLogEntry('System', '✅ 5 credits added. The council awaits.', false);
        }

        async function upgradePremium() {
            addLogEntry('System', '👑 Upgrade to Premium: $47/month. (Demo: activated)', false);
            userTier = 'premium';
            addRevenue(47);
            saveUserState();
            updateUI();
            addLogEntry('System', '✅ Premium tier activated. You have 20 questions per month.', false);
        }

        async function executiveSession() {
            addLogEntry('System', '⚡ Executive Session: $497. (Demo: activated)', false);
            userTier = 'executive';
            addRevenue(497);
            saveUserState();
            updateUI();
            addLogEntry('System', '✅ Executive tier activated. Unlimited questions, priority response.', false);
        }

        // --- GODS DATA (Expanded PLT) ---
        const godsData = [
            {
                id: "profit_prime",
                name: "Profit Prime",
                title: "The Architect of Multiplication",
                plt_weights: { profit: 0.92, love: 0.18, tax: 0.68 },
                signature_phrases: ["That doesn't scale.", "The numbers don't support that.", "If it doesn't multiply, it doesn't matter.", "Speed is survival.", "We calculate, then we move."],
                voice_pref: { gender: "male", pitch: 0.4, rate: 0.85, color: 0xffaa44 },
                position: { x: -1.2, z: -1.2 }
            },
            {
                id: "love_weaver",
                name: "Love Weaver",
                title: "The Keeper of Bonds",
                plt_weights: { profit: 0.35, love: 0.91, tax: 0.52 },
                signature_phrases: ["That breaks trust.", "People will feel that.", "You're asking the wrong question.", "What are we protecting?", "Nothing grows that people do not stay for."],
                voice_pref: { gender: "female", pitch: 1.1, rate: 0.9, color: 0xff88aa },
                position: { x: 1.2, z: -1.2 }
            },
            {
                id: "tax_collector",
                name: "Tax Collector",
                title: "The Balancer of All Things",
                plt_weights: { profit: 0.45, love: 0.22, tax: 0.94 },
                signature_phrases: ["That has a cost.", "You will pay for that later.", "Everything is accounted for.", "If not now, later.", "All things are paid for."],
                voice_pref: { gender: "neutral", pitch: 0.9, rate: 0.95, color: 0x88aaff },
                position: { x: 1.2, z: 1.2 }
            },
            {
                id: "harvester",
                name: "Harvester",
                title: "The Finder of Opportunity",
                plt_weights: { profit: 0.82, love: 0.45, tax: 0.58 },
                signature_phrases: ["There's an opening here.", "We're missing something.", "The window is now.", "Find the gap.", "The harvest takes what is ripe."],
                voice_pref: { gender: "male", pitch: 1.0, rate: 1.1, color: 0x88ffaa },
                position: { x: -1.2, z: 1.2 }
            }
        ];

        // --- RESPONSE GENERATOR (PLT-Weighted, Tier-Aware) ---
        function generateGodResponse(god, userInput, userTier) {
            const lower = userInput.toLowerCase();
            let position = 'balanced';
            let confidence = 0.6;

            const isMoney = lower.includes('money') || lower.includes('growth') || lower.includes('fast');
            const isTrust = lower.includes('trust') || lower.includes('people') || lower.includes('burnout');
            const isCost = lower.includes('cost') || lower.includes('risk');

            if (god.id === 'profit_prime') {
                if (isMoney) { position = 'aggressive'; confidence = 0.85; }
                else if (isTrust) { position = 'cautious'; confidence = 0.7; }
            } else if (god.id === 'love_weaver') {
                if (isTrust) { position = 'protective'; confidence = 0.88; }
                else if (isMoney) { position = 'cautious'; confidence = 0.75; }
            } else if (god.id === 'tax_collector') {
                if (isCost || isMoney) { position = 'cautious'; confidence = 0.9; }
            } else if (god.id === 'harvester') {
                if (isMoney) { position = 'aggressive'; confidence = 0.82; }
            }

            // Tier-aware response framing
            let tierPrefix = '';
            if (userTier === 'executive') {
                tierPrefix = 'Executive access granted. ';
            } else if (userTier === 'premium') {
                tierPrefix = 'Premium counsel: ';
            }

            const phrases = god.signature_phrases;
            const signature = phrases[Math.floor(Math.random() * phrases.length)];

            let text = "";
            if (position === 'aggressive') {
                text = `${signature} The window is open. We strike now.`;
            } else if (position === 'cautious') {
                text = `${signature} Speed without reckoning is collapse. We wait.`;
            } else if (position === 'protective') {
                text = `${signature} What we build matters less than who stays. Protect the bond.`;
            } else {
                text = `${signature} The answer lies between. Let the council decide.`;
            }

            return { text: tierPrefix + text, position, confidence };
        }

        // --- VOICE MANAGER ---
        class VoiceManager {
            constructor() {
                this.voices = [];
                this.ready = false;
                if ('speechSynthesis' in window) {
                    window.speechSynthesis.onvoiceschanged = () => {
                        this.voices = window.speechSynthesis.getVoices();
                        this.ready = true;
                    };
                    this.voices = window.speechSynthesis.getVoices();
                }
            }
            speak(text, pref) {
                if (!this.ready || !window.speechSynthesis) return;
                window.speechSynthesis.cancel();
                const utterance = new SpeechSynthesisUtterance(text);
                let bestVoice = null;
                for (const voice of this.voices) {
                    if (pref.gender === 'male' && voice.name.includes('Male')) bestVoice = voice;
                    if (pref.gender === 'female' && voice.name.includes('Female')) bestVoice = voice;
                }
                if (bestVoice) utterance.voice = bestVoice;
                utterance.pitch = pref.pitch || 1;
                utterance.rate = pref.rate || 1;
                window.speechSynthesis.speak(utterance);
            }
        }

        // --- 3D SCENE (same as before, compressed) ---
        const container = document.getElementById('canvas-container');
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x030318);
        scene.fog = new THREE.FogExp2(0x030318, 0.008);
        const camera = new THREE.PerspectiveCamera(45, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(0, 2, 8);
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        container.appendChild(renderer.domElement);
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.autoRotate = true;
        controls.autoRotateSpeed = 0.2;
        controls.target.set(0, 1, 0);

        const ambient = new THREE.AmbientLight(0x331144, 0.5);
        scene.add(ambient);
        const mainLight = new THREE.DirectionalLight(0xffcc88, 1.2);
        mainLight.position.set(3, 5, 2);
        scene.add(mainLight);

        const platformGeo = new THREE.CylinderGeometry(3.5, 3.8, 0.2, 32);
        const platformMat = new THREE.MeshStandardMaterial({ color: 0x221133, metalness: 0.7 });
        const platform = new THREE.Mesh(platformGeo, platformMat);
        platform.position.y = -0.5;
        scene.add(platform);

        const ringGeo = new THREE.TorusGeometry(3.8, 0.05, 64, 200);
        const ringMat = new THREE.MeshStandardMaterial({ color: 0xffaa66, emissive: 0x442200 });
        const ring = new THREE.Mesh(ringGeo, ringMat);
        ring.rotation.x = Math.PI / 2;
        ring.position.y = -0.35;
        scene.add(ring);

        const godMeshes = [];
        godsData.forEach((god) => {
            const geo = god.id === 'profit_prime' ? new THREE.CylinderGeometry(0.5, 0.6, 0.9, 8) :
                       god.id === 'love_weaver' ? new THREE.SphereGeometry(0.55, 32, 32) :
                       god.id === 'tax_collector' ? new THREE.ConeGeometry(0.5, 0.9, 6) :
                       new THREE.TetrahedronGeometry(0.6);
            const mat = new THREE.MeshStandardMaterial({ color: god.voice_pref.color, emissive: god.voice_pref.color, emissiveIntensity: 0.4 });
            const mesh = new THREE.Mesh(geo, mat);
            mesh.position.set(god.position.x, 0.2, god.position.z);
            mesh.userData = { god, isSpeaking: false, baseY: 0.2 };
            scene.add(mesh);
            godMeshes.push(mesh);
        });

        const particleCount = 4000;
        const particleGeo = new THREE.BufferGeometry();
        const positions = new Float32Array(particleCount * 3);
        for (let i = 0; i < particleCount; i++) {
            positions[i*3] = (Math.random() - 0.5) * 20;
            positions[i*3+1] = Math.random() * 5 - 1;
            positions[i*3+2] = (Math.random() - 0.5) * 15;
        }
        particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
        const particles = new THREE.Points(particleGeo, new THREE.PointsMaterial({ color: 0x88aaff, size: 0.03, blending: THREE.AdditiveBlending }));
        scene.add(particles);

        const renderScene = new RenderPass(scene, camera);
        const bloomPass = new UnrealBloomPass(new THREE.Vector2(window.innerWidth, window.innerHeight), 1.0, 0.3, 0.85);
        const composer = new EffectComposer(renderer);
        composer.addPass(renderScene);
        composer.addPass(bloomPass);

        // --- UI LOGIC ---
        const voiceManager = new VoiceManager();
        const logPanel = document.getElementById('logPanel');
        const userInput = document.getElementById('userInput');

        function addLogEntry(speaker, message, isGod = true) {
            const entry = document.createElement('div');
            entry.className = 'log-entry';
            entry.innerHTML = isGod ? `<span style="color:#ffaa66;">🗣️ ${speaker}:</span> ${message}` : `<span style="color:#88ffaa;">📜 ${speaker}:</span> ${message}`;
            logPanel.appendChild(entry);
            entry.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
            while (logPanel.children.length > 35) logPanel.removeChild(logPanel.firstChild);
        }

        async function sendMessage(text) {
            if (!text.trim()) return;
            if (!canAskQuestion()) {
                addLogEntry('System', '⚠️ You have no questions remaining. Upgrade or buy credits.', false);
                return;
            }

            addLogEntry('You', text, false);
            userInput.value = '';
            document.getElementById('status').innerHTML = '⏳ Gods deliberating...';

            consumeQuestion();

            // Animate gods
            godMeshes.forEach(m => { m.userData.isSpeaking = true; setTimeout(() => { m.userData.isSpeaking = false; }, 800); });

            for (const god of godsData) {
                const response = generateGodResponse(god, text, userTier);
                addLogEntry(god.name, response.text, true);
                voiceManager.speak(response.text, god.voice_pref);
                await new Promise(r => setTimeout(r, 1200));
            }

            document.getElementById('status').innerHTML = '🟢 Council listening';
        }

        // Event binding
        document.getElementById('sendBtn').onclick = () => sendMessage(userInput.value);
        document.getElementById('buyCreditsBtn').onclick = buyCredits;
        document.getElementById('upgradePremiumBtn').onclick = upgradePremium;
        document.getElementById('executiveSessionBtn').onclick = executiveSession;
        userInput.onkeypress = (e) => { if (e.key === 'Enter') sendMessage(userInput.value); };

        // Tier selector
        document.querySelectorAll('.tier-btn').forEach(btn => {
            btn.onclick = () => {
                addLogEntry('System', `Selected ${btn.dataset.tier} tier view. Upgrade to activate.`, false);
            };
        });

        // Mic
        if ('webkitSpeechRecognition' in window) {
            const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
            const recognition = new SpeechRecognition();
            recognition.lang = 'en-US';
            recognition.onresult = (e) => { userInput.value = e.results[0][0].transcript; sendMessage(userInput.value); };
            document.getElementById('micBtn').onclick = () => recognition.start();
        }

        // Animation
        let time = 0;
        function animate() {
            requestAnimationFrame(animate);
            time += 0.016;
            godMeshes.forEach((mesh, i) => {
                mesh.position.y = mesh.userData.baseY + Math.sin(time * 1.5 + i) * 0.05;
                mesh.material.emissiveIntensity = mesh.userData.isSpeaking ? 0.8 + Math.sin(time * 15) * 0.2 : 0.3;
            });
            ring.rotation.z += 0.005;
            particles.rotation.y += 0.0005;
            controls.update();
            composer.render();
        }
        animate();

        // Initialize
        loadUserState();
        addLogEntry('System', '🏛️ Pantheon v2 — Tiered Access, Credits, Commerce. Choose your tier.', false);
    </script>
</body>
</html>
