            border: 1px solid #ffaa44;
            padding: 8px 8px 8px 20px;
            display: flex;
            gap: 10px;
        }

        .input-panel input {
            flex: 1;
            background: transparent;
            border: none;
            color: #ffdd99;
            font-size: 16px;
            font-family: monospace;
            outline: none;
        }

        .log-panel {
            position: absolute;
            bottom: 20px;
            left: 20px;
            width: 340px;
            max-height: 300px;
            overflow-y: auto;
            background: rgba(0, 0, 0, 0.6);
            backdrop-filter: blur(8px);
            border-radius: 12px;
            padding: 10px;
            font-size: 11px;
            z-index: 90;
            border-left: 2px solid #ffaa44;
        }

        .status {
            position: absolute;
            top: 20px;
            left: 260px;
            background: rgba(0,0,0,0.6);
            padding: 6px 12px;
            border-radius: 20px;
            font-size: 10px;
            z-index: 90;
        }

        .memory-badge {
            position: absolute;
            bottom: 100px;
            right: 20px;
            background: rgba(0,0,0,0.5);
            padding: 4px 10px;
            border-radius: 12px;
            font-size: 9px;
            font-family: monospace;
            z-index: 90;
        }
    </style>
</head>
<body>

    <div id="canvas-container"></div>

    <!-- Auth Panel -->
    <div class="auth-panel" id="authPanel">
        <div id="authContent">
            <!-- Dynamic auth UI -->
        </div>
    </div>

    <!-- Commerce Panel -->
    <div class="commerce-panel" id="commercePanel" style="display: none;">
        <div style="font-size: 12px;">💰 THE VAULT</div>
        <div class="vault-display" id="vaultDisplay">$0.00</div>
        <div class="credit-badge">🎫 Credits: <span id="creditCount">0</span></div>
        <div class="tier-selector">
            <button class="tier-btn" data-tier="free">🎁 Free</button>
            <button class="tier-btn" data-tier="premium">👑 Premium</button>
            <button class="tier-btn" data-tier="executive">⚡ Executive</button>
        </div>
        <button class="support-btn" id="buyCreditsBtn">🎫 Buy 5 Credits ($47)</button>
        <button class="support-btn secondary" id="upgradePremiumBtn">👑 Upgrade Premium ($47/mo)</button>
        <button class="support-btn secondary" id="executiveSessionBtn">⚡ Executive Session ($497)</button>
        <div class="credit-badge" style="font-size: 10px; margin-top: 8px;" id="tierInfo"></div>
    </div>

    <div class="input-panel" id="inputPanel" style="display: none;">
        <input type="text" id="userInput" placeholder="Speak to the council...">
        <button id="micBtn">🎤</button>
        <button id="sendBtn">⚡ SPEAK</button>
    </div>

    <div class="log-panel" id="logPanel">
        <div class="log-entry">🏛️ Welcome to the Pantheon. Please log in to begin.</div>
    </div>

    <div class="status" id="status">🔐 Not logged in</div>
    <div class="memory-badge" id="memoryBadge" style="display: none;">📜 Seshat: 0 memories</div>

    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.128.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.128.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
        import { EffectComposer } from 'three/addons/postprocessing/EffectComposer.js';
        import { RenderPass } from 'three/addons/postprocessing/RenderPass.js';
        import { UnrealBloomPass } from 'three/addons/postprocessing/UnrealBloomPass.js';

        // ============================================================
        // PANTHEON v3 — User Accounts, Seshat Memory, Commerce
        // ============================================================

        // --- DATA STORES (Simulated Backend) ---
        // In production, this would be a real database. For demo, we use localStorage
        // with user-specific namespaces.

        let currentUser = null;

        // User database (stored in localStorage as 'pantheon_users')
        function getUsers() {
            const users = localStorage.getItem('pantheon_users');
            return users ? JSON.parse(users) : {};
        }

        function saveUsers(users) {
            localStorage.setItem('pantheon_users', JSON.stringify(users));
        }

        // User-specific data
        function getUserData(email) {
            const key = `pantheon_user_${email.replace(/[^a-z0-9]/gi, '_')}`;
            const data = localStorage.getItem(key);
            if (data) return JSON.parse(data);
            return {
                email,
                tier: 'free',
                credits: 0,
                questionsUsedToday: 0,
                lastResetDate: new Date().toDateString(),
                totalSpent: 0,
                createdAt: Date.now(),
                memories: []  // Seshat memory store
            };
        }

        function saveUserData(email, data) {
            const key = `pantheon_user_${email.replace(/[^a-z0-9]/gi, '_')}`;
            localStorage.setItem(key, JSON.stringify(data));
        }

        // Auth functions
        function login(email, password) {
            const users = getUsers();
            if (!users[email]) {
                // Create new user
                users[email] = { email, password, createdAt: Date.now() };
                saveUsers(users);
                const userData = getUserData(email);
                saveUserData(email, userData);
                currentUser = { email, ...userData };
                return true;
            } else if (users[email].password === password) {
                const userData = getUserData(email);
                currentUser = { email, ...userData };
                return true;
            }
            return false;
        }

        function logout() {
            if (currentUser) {
                // Save current state before logout
                const userData = { ...currentUser };
                delete userData.email;
                saveUserData(currentUser.email, userData);
            }
            currentUser = null;
        }

        function updateCurrentUser(updates) {
            if (!currentUser) return;
            Object.assign(currentUser, updates);
            const userData = { ...currentUser };
            delete userData.email;
            saveUserData(currentUser.email, userData);
            updateUI();
        }

        // Daily reset
        function checkDailyReset() {
            if (!currentUser) return;
            const today = new Date().toDateString();
            if (currentUser.lastResetDate !== today) {
                currentUser.questionsUsedToday = 0;
                currentUser.lastResetDate = today;
                updateCurrentUser({ questionsUsedToday: 0, lastResetDate: today });
            }
        }

        // Credit management
        function canAskQuestion() {
            if (!currentUser) return false;
            checkDailyReset();
            if (currentUser.tier === 'executive') return true;
            if (currentUser.tier === 'premium') return currentUser.credits > 0;
            if (currentUser.tier === 'free') return currentUser.questionsUsedToday < 1;
            return false;
        }

        function consumeQuestion() {
            if (!canAskQuestion()) return false;
            if (currentUser.tier === 'executive') return true;
            if (currentUser.tier === 'premium') {
                updateCurrentUser({ credits: currentUser.credits - 1 });
                return true;
            }
            if (currentUser.tier === 'free') {
                updateCurrentUser({ questionsUsedToday: currentUser.questionsUsedToday + 1 });
                return true;
            }
            return false;
        }

        function addCredits(amount) {
            updateCurrentUser({ credits: (currentUser.credits || 0) + amount });
        }

        function addRevenue(amount) {
            const newSpent = (currentUser.totalSpent || 0) + amount;
            updateCurrentUser({ totalSpent: newSpent });
            // Also update global vault display
            updateVaultDisplay();
        }

        function setTier(tier) {
            updateCurrentUser({ tier });
        }

        // --- SESHAT MEMORY SYSTEM ---
        function addMemory(question, responses) {
            if (!currentUser) return;
            const memory = {
                id: Date.now(),
                timestamp: new Date().toISOString(),
                question,
                responses: responses.map(r => ({ god: r.god, text: r.text })),
                tags: extractTags(question)
            };
            const memories = [...(currentUser.memories || []), memory];
            // Keep last 50 memories
            if (memories.length > 50) memories.shift();
            updateCurrentUser({ memories });
            updateMemoryBadge();
        }

        function extractTags(question) {
            const tags = [];
            const lower = question.toLowerCase();
            if (lower.includes('money') || lower.includes('growth')) tags.push('profit');
            if (lower.includes('trust') || lower.includes('people')) tags.push('love');
            if (lower.includes('cost') || lower.includes('risk')) tags.push('tax');
            if (lower.includes('opportunity') || lower.includes('window')) tags.push('harvest');
            if (tags.length === 0) tags.push('general');
            return tags;
        }

        function getRelevantMemories(question, limit = 3) {
            if (!currentUser || !currentUser.memories) return [];
            const tags = extractTags(question);
            const scored = currentUser.memories.map(memory => {
                let score = 0;
                memory.tags.forEach(tag => {
                    if (tags.includes(tag)) score += 0.4;
                });
                // Recency bonus
                const age = Date.now() - memory.id;
                const recency = Math.max(0, 1 - (age / (30 * 24 * 60 * 60 * 1000)));
                score += recency * 0.2;
                return { memory, score };
            });
            return scored.sort((a, b) => b.score - a.score).slice(0, limit).map(s => s.memory);
        }

        // --- UI Updates ---
        function updateUI() {
            const authContent = document.getElementById('authContent');
            const commercePanel = document.getElementById('commercePanel');
            const inputPanel = document.getElementById('inputPanel');
            const statusEl = document.getElementById('status');

            if (!currentUser) {
                authContent.innerHTML = `
                    <div class="user-info">🔐 <strong>Pantheon Access</strong></div>
                    <div class="login-form">
                        <input type="email" id="loginEmail" placeholder="Email" style="margin-bottom: 5px;">
                        <input type="password" id="loginPassword" placeholder="Password">
                        <button id="loginBtn" class="logout-btn" style="width: 100%; margin-top: 8px;">Enter the Hall</button>
                    </div>
                    <div style="font-size: 9px; margin-top: 8px; color: #8866aa;">New soul? Enter email to begin.</div>
                `;
                commercePanel.style.display = 'none';
                inputPanel.style.display = 'none';
                statusEl.innerHTML = '🔐 Not logged in';
                document.getElementById('memoryBadge').style.display = 'none';

                document.getElementById('loginBtn')?.addEventListener('click', () => {
                    const email = document.getElementById('loginEmail').value;
                    const password = document.getElementById('loginPassword').value;
                    if (email && login(email, password)) {
                        updateUI();
                        addLogEntry('System', `Welcome, ${email}. The council awaits.`, false);
                    } else {
                        alert('Invalid credentials');
                    }
                });
                return;
            }

            // Logged in UI
            checkDailyReset();
            authContent.innerHTML = `
                <div class="user-info">👑 <span class="user-email">${currentUser.email}</span></div>
                <div class="user-info">🎫 ${currentUser.tier.toUpperCase()} tier</div>
                <button id="logoutBtn" class="logout-btn">Leave the Hall</button>
            `;
            commercePanel.style.display = 'block';
            inputPanel.style.display = 'block';
            statusEl.innerHTML = `🟢 ${currentUser.tier.toUpperCase()} · ${currentUser.credits} credits · ${currentUser.questionsUsedToday}/1 free`;
            document.getElementById('memoryBadge').style.display = 'block';

            document.getElementById('creditCount').innerText = currentUser.credits || 0;
            document.getElementById('tierInfo').innerHTML = currentUser.tier === 'free' ? 'Free: 1 question/day' :
                                                           currentUser.tier === 'premium' ? 'Premium: 20 questions/mo' :
                                                           'Executive: Unlimited';

            // Highlight active tier
            document.querySelectorAll('.tier-btn').forEach(btn => {
                if (btn.dataset.tier === currentUser.tier) btn.classList.add('active');
                else btn.classList.remove('active');
            });

            document.getElementById('logoutBtn')?.addEventListener('click', () => {
                logout();
                updateUI();
                addLogEntry('System', 'You have left the hall. Return when ready.', false);
            });

            updateVaultDisplay();
            updateMemoryBadge();
        }

        function updateVaultDisplay() {
            if (!currentUser) return;
            const vaultEl = document.getElementById('vaultDisplay');
            if (vaultEl) {
                vaultEl.innerHTML = `$${(currentUser.totalSpent || 0).toFixed(2)}`;
            }
        }

        function updateMemoryBadge() {
            const count = currentUser?.memories?.length || 0;
            const badge = document.getElementById('memoryBadge');
            if (badge) {
                badge.innerHTML = `📜 Seshat: ${count} memories`;
            }
        }

        // --- GODS DATA ---
        const godsData = [
            {
                id: "profit_prime",
                name: "Profit Prime",
                plt_weights: { profit: 0.92, love: 0.18, tax: 0.68 },
                signature_phrases: ["That doesn't scale.", "The numbers don't support that.", "If it doesn't multiply, it doesn't matter.", "Speed is survival."],
                voice_pref: { gender: "male", pitch: 0.4, rate: 0.85, color: 0xffaa44 },
                position: { x: -1.2, z: -1.2 }
            },
            {
                id: "love_weaver",
                name: "Love Weaver",
                plt_weights: { profit: 0.35, love: 0.91, tax: 0.52 },
                signature_phrases: ["That breaks trust.", "People will feel that.", "You're asking the wrong question.", "Nothing grows that people do not stay for."],
                voice_pref: { gender: "female", pitch: 1.1, rate: 0.9, color: 0xff88aa },
                position: { x: 1.2, z: -1.2 }
            },
            {
                id: "tax_collector",
                name: "Tax Collector",
                plt_weights: { profit: 0.45, love: 0.22, tax: 0.94 },
                signature_phrases: ["That has a cost.", "You will pay for that later.", "Everything is accounted for.", "If not now, later."],
                voice_pref: { gender: "neutral", pitch: 0.9, rate: 0.95, color: 0x88aaff },
                position: { x: 1.2, z: 1.2 }
            },
            {
                id: "harvester",
                name: "Harvester",
                plt_weights: { profit: 0.82, love: 0.45, tax: 0.58 },
                signature_phrases: ["There's an opening here.", "We're missing something.", "The window is now.", "Find the gap."],
                voice_pref: { gender: "male", pitch: 1.0, rate: 1.1, color: 0x88ffaa },
                position: { x: -1.2, z: 1.2 }
            }
        ];

        // --- RESPONSE GENERATOR (with Memory Integration) ---
        function generateGodResponse(god, userInput, relevantMemories) {
            const lower = userInput.toLowerCase();
            let position = 'balanced';
            let confidence = 0.6;

            const isMoney = lower.includes('money') || lower.includes('growth') || lower.includes('fast');
            const isTrust = lower.includes('trust') || lower.includes('people') || lower.includes('burnout');
            const isCost = lower.includes('cost') || lower.includes('risk');

            if (god.id === 'profit_prime') {
                if (isMoney) { position = 'aggressive'; confidence = 0.85; }
                else if (isTrust) { position = 'cautious'; confidence = 0.7; }
            } else if (god.id === 'love_weaver') {
                if (isTrust) { position = 'protective'; confidence = 0.88; }
                else if (isMoney) { position = 'cautious'; confidence = 0.75; }
            } else if (god.id === 'tax_collector') {
                if (isCost || isMoney) { position = 'cautious'; confidence = 0.9; }
            } else if (god.id === 'harvester') {
                if (isMoney) { position = 'aggressive'; confidence = 0.82; }
            }

            // Memory reference if relevant
            let memoryRef = '';
            if (relevantMemories.length > 0 && Math.random() > 0.6) {
                const mem = relevantMemories[0];
                memoryRef = ` You asked about ${mem.tags[0]} before. `;
            }

            const phrases = god.signature_phrases;
            const signature = phrases[Math.floor(Math.random() * phrases.length)];

            let text = "";
            if (position === 'aggressive') {
                text = `${signature}${memoryRef} The window is open. We strike now.`;
            } else if (position === 'cautious') {
                text = `${signature}${memoryRef} Speed without reckoning is collapse. We wait.`;
            } else if (position === 'protective') {
                text = `${signature}${memoryRef} What we build matters less than who stays. Protect the bond.`;
            } else {
                text = `${signature}${memoryRef} The answer lies between. Let the council decide.`;
            }

            // Tier framing
            if (currentUser.tier === 'executive') {
                text = `[Executive insight] ${text}`;
            } else if (currentUser.tier === 'premium') {
                text = `Premium counsel: ${text}`;
            }

            return { text, position, confidence };
        }

        // --- VOICE MANAGER ---
        class VoiceManager {
            constructor() {
                this.voices = [];
                this.ready = false;
                if ('speechSynthesis' in window) {
                    window.speechSynthesis.onvoiceschanged = () => {
                        this.voices = window.speechSynthesis.getVoices();
                        this.ready = true;
                    };
                    this.voices = window.speechSynthesis.getVoices();
                }
            }
            speak(text, pref) {
                if (!this.ready || !window.speechSynthesis) return;
                window.speechSynthesis.cancel();
                const utterance = new SpeechSynthesisUtterance(text);
                let bestVoice = null;
                for (const voice of this.voices) {
                    if (pref.gender === 'male' && voice.name.includes('Male')) bestVoice = voice;
                    if (pref.gender === 'female' && voice.name.includes('Female')) bestVoice = voice;
                }
                if (bestVoice) utterance.voice = bestVoice;
                utterance.pitch = pref.pitch || 1;
                utterance.rate = pref.rate || 1;
                window.speechSynthesis.speak(utterance);
            }
        }

        // --- 3D SCENE (Compressed) ---
        const container = document.getElementById('canvas-container');
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x030318);
        scene.fog = new THREE.FogExp2(0x030318, 0.008);
        const camera = new THREE.PerspectiveCamera(45, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(0, 2, 8);
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        container.appendChild(renderer.domElement);
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.autoRotate = true;
        controls.autoRotateSpeed = 0.2;
        controls.target.set(0, 1, 0);

        const ambient = new THREE.AmbientLight(0x331144, 0.5);
        scene.add(ambient);
        const mainLight = new THREE.DirectionalLight(0xffcc88, 1.2);
        mainLight.position.set(3, 5, 2);
        scene.add(mainLight);

        const platformGeo = new THREE.CylinderGeometry(3.5, 3.8, 0.2, 32);
        const platformMat = new THREE.MeshStandardMaterial({ color: 0x221133, metalness: 0.7 });
        const platform = new THREE.Mesh(platformGeo, platformMat);
        platform.position.y = -0.5;
        scene.add(platform);

        const ringGeo = new THREE.TorusGeometry(3.8, 0.05, 64, 200);
        const ringMat = new THREE.MeshStandardMaterial({ color: 0xffaa66, emissive: 0x442200 });
        const ring = new THREE.Mesh(ringGeo, ringMat);
        ring.rotation.x = Math.PI / 2;
        ring.position.y = -0.35;
        scene.add(ring);

        const godMeshes = [];
        godsData.forEach((god) => {
            const geo = god.id === 'profit_prime' ? new THREE.CylinderGeometry(0.5, 0.6, 0.9, 8) :
                       god.id === 'love_weaver' ? new THREE.SphereGeometry(0.55, 32, 32) :
                       god.id === 'tax_collector' ? new THREE.ConeGeometry(0.5, 0.9, 6) :
                       new THREE.TetrahedronGeometry(0.6);
            const mat = new THREE.MeshStandardMaterial({ color: god.voice_pref.color, emissive: god.voice_pref.color, emissiveIntensity: 0.4 });
            const mesh = new THREE.Mesh(geo, mat);
            mesh.position.set(god.position.x, 0.2, god.position.z);
            mesh.userData = { god, isSpeaking: false, baseY: 0.2 };
            scene.add(mesh);
            godMeshes.push(mesh);
        });

        const particleCount = 4000;
        const particleGeo = new THREE.BufferGeometry();
        const positions = new Float32Array(particleCount * 3);
        for (let i = 0; i < particleCount; i++) {
            positions[i*3] = (Math.random() - 0.5) * 20;
            positions[i*3+1] = Math.random() * 5 - 1;
            positions[i*3+2] = (Math.random() - 0.5) * 15;
        }
        particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
        const particles = new THREE.Points(particleGeo, new THREE.PointsMaterial({ color: 0x88aaff, size: 0.03, blending: THREE.AdditiveBlending }));
        scene.add(particles);

        const renderScene = new RenderPass(scene, camera);
        const bloomPass = new UnrealBloomPass(new THREE.Vector2(window.innerWidth, window.innerHeight), 1.0, 0.3, 0.85);
        const composer = new EffectComposer(renderer);
        composer.addPass(renderScene);
        composer.addPass(bloomPass);

        // --- UI LOGIC ---
        const voiceManager = new VoiceManager();
        const logPanel = document.getElementById('logPanel');
        const userInput = document.getElementById('userInput');

        function addLogEntry(speaker, message, isGod = true) {
            const entry = document.createElement('div');
            entry.className = 'log-entry';
            entry.innerHTML = isGod ? `<span style="color:#ffaa66;">🗣️ ${speaker}:</span> ${message}` : `<span style="color:#88ffaa;">📜 ${speaker}:</span> ${message}`;
            logPanel.appendChild(entry);
            entry.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
            while (logPanel.children.length > 45) logPanel.removeChild(logPanel.firstChild);
        }

        async function sendMessage(text) {
            if (!currentUser) {
                addLogEntry('System', 'Please log in to speak with the council.', false);
                return;
            }
            if (!canAskQuestion()) {
                addLogEntry('System', `⚠️ No questions remaining. ${currentUser.tier === 'free' ? 'Upgrade or wait until tomorrow.' : 'Buy more credits or upgrade to Executive.'}`, false);
                return;
            }

            addLogEntry('You', text, false);
            userInput.value = '';
            document.getElementById('status').innerHTML = '⏳ Gods deliberating...';

            // Retrieve relevant memories for this question
            const relevantMemories = getRelevantMemories(text);
            if (relevantMemories.length > 0) {
                addLogEntry('Seshat', `Remembering ${relevantMemories.length} past ${relevantMemories[0].tags[0]} conversation...`, false);
            }

            consumeQuestion();

            // Animate gods
            godMeshes.forEach(m => { m.userData.isSpeaking = true; setTimeout(() => { m.userData.isSpeaking = false; }, 800); });

            const responses = [];
            for (const god of godsData) {
                const response = generateGodResponse(god, text, relevantMemories);
                responses.push({ god: god.name, text: response.text });
                addLogEntry(god.name, response.text, true);
                voiceManager.speak(response.text, god.voice_pref);
                await new Promise(r => setTimeout(r, 1000));
            }

            // Store in Seshat memory
            addMemory(text, responses);

            document.getElementById('status').innerHTML = `🟢 ${currentUser.tier.toUpperCase()} · ${currentUser.credits} credits · ${currentUser.questionsUsedToday}/1 free`;
            updateUI();
        }

        // Commerce handlers
        function buyCredits() {
            addCredits(5);
            addRevenue(47);
            addLogEntry('System', '✅ 5 credits added. Thank you for supporting the council.', false);
            updateUI();
        }

        function upgradePremium() {
            setTier('premium');
            addRevenue(47);
            addLogEntry('System', '👑 Premium tier activated. 20 questions per month. Welcome.', false);
            updateUI();
        }

        function executiveSession() {
            setTier('executive');
            addRevenue(497);
            addLogEntry('System', '⚡ Executive tier activated. Unlimited questions, priority response. The council is yours.', false);
            updateUI();
        }

        // Event binding
        document.getElementById('sendBtn')?.addEventListener('click', () => sendMessage(userInput.value));
        document.getElementById('buyCreditsBtn')?.addEventListener('click', buyCredits);
        document.getElementById('upgradePremiumBtn')?.addEventListener('click', upgradePremium);
        document.getElementById('executiveSessionBtn')?.addEventListener('click', executiveSession);
        userInput?.addEventListener('keypress', (e) => { if (e.key === 'Enter') sendMessage(userInput.value); });

        // Tier selector info
        document.querySelectorAll('.tier-btn').forEach(btn => {
            btn.addEventListener('click', () => {
                if (currentUser) {
                    addLogEntry('System', `Viewing ${btn.dataset.tier} tier. Upgrade to activate.`, false);
                }
            });
        });

        // Mic
        if ('webkitSpeechRecognition' in window) {
            const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
            const recognition = new SpeechRecognition();
            recognition.lang = 'en-US';
            recognition.onresult = (e) => { userInput.value = e.results[0][0].transcript; sendMessage(userInput.value); };
            document.getElementById('micBtn')?.addEventListener('click', () => recognition.start());
        }

        // Animation loop
        let time = 0;
        function animate() {
            requestAnimationFrame(animate);
