            if (relevantMemories.length > 0) {
                addLogEntry('Seshat', `I remember ${relevantMemories.length} conversations about ${relevantMemories[0].tags[0]}...`, false);
            }

            const responses = [];

            for (const god of godsData) {
                const response = generateGodResponse(god, text, relevantMemories);
                responses.push({ god: god.name, text: response.text });
                addLogEntry(god.name, response.text, true);

                const hasMemory = relevantMemories.length > 0;
