// ============================================================
// SESHKRAKEN — The Data Collector
// Tracks every user message, builds personality profiles,
// stores everything in the repository vault
// ============================================================

class SeshKraken {
    constructor(repoPath = './data/vault/') {
        this.repoPath = repoPath;
        this.users = new Map();
        this.init();
    }

    init() {
        // Load existing users from repo if running in Node
        try {
            const fs = require('fs');
            if (fs.existsSync(`${this.repoPath}index.json`)) {
                const index = JSON.parse(fs.readFileSync(`${this.repoPath}index.json`));
                index.users.forEach(user => this.users.set(user.id, user));
            }
        } catch(e) { console.log('Browser mode — using localStorage'); }
    }

    // Record a user message
    recordMessage(userId, message, context = {}) {
        const timestamp = Date.now();
        const messageRecord = {
            id: `${userId}_${timestamp}`,
            userId,
            message,
            context: {
                topic: this.detectTopic(message),
                emotionalWeight: this.calculateEmotionalWeight(message),
                source: context.source || 'pantheon',
                timestamp
            },
            response: null,
            outcome: null
        };

        this.storeMessage(messageRecord);
        this.updatePersonalityProfile(userId, message);
        return messageRecord;
    }

    // Record a god's response
    recordResponse(messageId, godName, responseText, evaluation) {
        const responseRecord = {
            messageId,
            god: godName,
            response: responseText,
            evaluation: {
                position: evaluation.finalPosition,
                confidence: evaluation.confidence,
                impulses: evaluation.impulses
            },
            timestamp: Date.now()
        };
        this.storeResponse(responseRecord);
    }

    // Record outcome (what happened after the advice)
    recordOutcome(messageId, outcome) {
        const outcomeRecord = {
            messageId,
            outcome: outcome.type,
            result: outcome.result,
            revenueImpact: outcome.revenueImpact || 0,
            timestamp: Date.now()
        };
        this.storeOutcome(outcomeRecord);
    }

    // Build/update personality profile for a user
    updatePersonalityProfile(userId, message) {
        let profile = this.getPersonalityProfile(userId);

        // Extract traits from message
        const traits = this.extractTraits(message);

        // Update aggregate personality
        profile.messageCount++;
        profile.lastActive = Date.now();

        // Update PLT affinity
        profile.plt.profit += traits.profit || 0;
        profile.plt.love += traits.love || 0;
        profile.plt.tax += traits.tax || 0;

        // Update emotional signature
        profile.emotionalSignature.push({
            emotion: traits.emotion || 'neutral',
            intensity: traits.intensity || 0.5,
            timestamp: Date.now()
        });
        // Keep last 50
        if (profile.emotionalSignature.length > 50) profile.emotionalSignature.shift();

        // Update topics of interest
        traits.topics.forEach(topic => {
            profile.topics[topic] = (profile.topics[topic] || 0) + 1;
        });

        // Update archetype based on PLT dominance
        const total = profile.plt.profit + profile.plt.love + profile.plt.tax;
        if (total > 10) {
            if (profile.plt.profit > profile.plt.love && profile.plt.profit > profile.plt.tax) {
                profile.archetype = 'The Strategist';
            } else if (profile.plt.love > profile.plt.profit && profile.plt.love > profile.plt.tax) {
                profile.archetype = 'The Weaver';
            } else if (profile.plt.tax > profile.plt.profit && profile.plt.tax > profile.plt.love) {
                profile.archetype = 'The Balancer';
            } else {
                profile.archetype = 'The Seeker';
            }
        }

        this.storePersonalityProfile(userId, profile);
        return profile;
    }

    extractTraits(message) {
        const lower = message.toLowerCase();
        const traits = {
            profit: 0,
            love: 0,
            tax: 0,
            emotion: 'neutral',
            intensity: 0.5,
            topics: []
        };

        // Profit keywords
        if (lower.includes('money') || lower.includes('growth') || lower.includes('fast') || 
            lower.includes('scale') || lower.includes('profit') || lower.includes('revenue')) {
            traits.profit += 0.3;
            traits.topics.push('profit');
        }

        // Love keywords
        if (lower.includes('trust') || lower.includes('people') || lower.includes('feel') ||
            lower.includes('connection') || lower.includes('relationship') || lower.includes('care')) {
            traits.love += 0.3;
            traits.topics.push('love');
        }

        // Tax keywords
        if (lower.includes('cost') || lower.includes('risk') || lower.includes('consequence') ||
            lower.includes('pay') || lower.includes('price') || lower.includes('worth')) {
            traits.tax += 0.3;
            traits.topics.push('tax');
        }

        // Emotional detection
        if (lower.includes('urgent') || lower.includes('desperate') || lower.includes('fast')) {
            traits.emotion = 'urgent';
            traits.intensity = 0.8;
        } else if (lower.includes('worried') || lower.includes('concerned') || lower.includes('afraid')) {
            traits.emotion = 'anxious';
            traits.intensity = 0.7;
        } else if (lower.includes('excited') || lower.includes('amazing') || lower.includes('great')) {
            traits.emotion = 'excited';
            traits.intensity = 0.8;
        } else if (lower.includes('thank') || lower.includes('grateful') || lower.includes('appreciate')) {
            traits.emotion = 'grateful';
            traits.intensity = 0.7;
        }

        return traits;
    }

    detectTopic(message) {
        const lower = message.toLowerCase();
        if (lower.includes('money') || lower.includes('growth')) return 'growth';
        if (lower.includes('trust') || lower.includes('people')) return 'trust';
        if (lower.includes('cost') || lower.includes('risk')) return 'cost';
        if (lower.includes('opportunity') || lower.includes('window')) return 'opportunity';
        return 'general';
    }

    calculateEmotionalWeight(message) {
        const lower = message.toLowerCase();
        let weight = 0.5;
        if (lower.includes('urgent')) weight += 0.2;
        if (lower.includes('desperate')) weight += 0.3;
        if (lower.includes('excited')) weight += 0.2;
        if (lower.includes('worried')) weight += 0.2;
        return Math.min(0.95, weight);
    }

    getPersonalityProfile(userId) {
        // Try to load from storage
        const stored = this.loadFromStorage(`personality_${userId}`);
        if (stored) return stored;

        // Return default profile
        return {
            userId,
            createdAt: Date.now(),
            lastActive: Date.now(),
            messageCount: 0,
            plt: { profit: 0, love: 0, tax: 0 },
            emotionalSignature: [],
            topics: {},
            archetype: 'The Seeker',
            valueScore: 0,
            lifetimeValue: 0,
            segments: []
        };
    }

    // Storage methods (adapts to environment)
    storeMessage(record) {
        if (typeof localStorage !== 'undefined') {
            const messages = JSON.parse(localStorage.getItem('seshat_messages') || '[]');
            messages.push(record);
            localStorage.setItem('seshat_messages', JSON.stringify(messages.slice(-1000)));
        }
        // In Node, write to file
        this.writeToRepo(`messages/${record.id}.json`, record);
    }

    storePersonalityProfile(userId, profile) {
        if (typeof localStorage !== 'undefined') {
            localStorage.setItem(`personality_${userId}`, JSON.stringify(profile));
        }
        this.writeToRepo(`personality/${userId}.json`, profile);
    }

    writeToRepo(path, data) {
        // In browser, this would be a GitHub API call
        // In Node, fs.writeFile
        if (typeof process !== 'undefined' && process.env.NODE_ENV === 'development') {
            try {
                const fs = require('fs');
                const fullPath = `${this.repoPath}${path}`;
                const dir = fullPath.substring(0, fullPath.lastIndexOf('/'));
                if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
                fs.writeFileSync(fullPath, JSON.stringify(data, null, 2));
            } catch(e) { console.log('Write failed:', e); }
        }
    }

    loadFromStorage(key) {
        if (typeof localStorage !== 'undefined') {
            const data = localStorage.getItem(key);
            return data ? JSON.parse(data) : null;
        }
        return null;
    }

    // Generate insights from collected data
    generateUserInsights(userId) {
        const profile = this.getPersonalityProfile(userId);
        const insights = {
            dominantPLT: this.getDominantPLT(profile),
            recommendedGod: this.getRecommendedGod(profile),
            emotionalPattern: this.getEmotionalPattern(profile),
            valueSegment: this.getValueSegment(profile),
            nextAction: this.getNextAction(profile)
        };
        return insights;
    }

    getDominantPLT(profile) {
        const { profit, love, tax } = profile.plt;
        if (profit > love && profit > tax) return 'Profit Prime';
        if (love > profit && love > tax) return 'Love Weaver';
        if (tax > profit && tax > love) return 'Tax Collector';
        return 'Harvester';
    }

    getRecommendedGod(profile) {
        const dominant = this.getDominantPLT(profile);
        switch(dominant) {
            case 'Profit Prime': return 'profit_prime';
            case 'Love Weaver': return 'love_weaver';
            case 'Tax Collector': return 'tax_collector';
            default: return 'harvester';
        }
    }

    getEmotionalPattern(profile) {
        const emotions = profile.emotionalSignature.map(e => e.emotion);
        const counts = {};
        emotions.forEach(e => counts[e] = (counts[e] || 0) + 1);
        const dominant = Object.entries(counts).sort((a,b) => b[1] - a[1])[0];
        return dominant ? dominant[0] : 'neutral';
    }

    getValueSegment(profile) {
        const ltv = profile.lifetimeValue || 0;
        if (ltv === 0) return 'free';
        if (ltv < 50) return 'low_value';
        if (ltv < 500) return 'medium_value';
        return 'high_value';
    }

    getNextAction(profile) {
        const segment = this.getValueSegment(profile);
        const dominant = this.getDominantPLT(profile);
        const lastActive = profile.lastActive;
        const daysSince = (Date.now() - lastActive) / (1000 * 60 * 60 * 24);

        if (daysSince > 30) return 're-engagement_email';
        if (segment === 'free' && profile.messageCount > 5) return 'offer_premium';
        if (dominant === 'Profit Prime') return 'share_growth_case_study';
        if (dominant === 'Love Weaver') return 'share_community_event';
        if (dominant === 'Tax Collector') return 'share_roi_report';
        return 'send_newsletter';
    }
}

export default SeshKraken;
