// ============================================================
// GITHUB SYNC — Push all vault data to repository
// ============================================================

class GitHubSync {
    constructor(owner, repo, token) {
        this.owner = owner;
        this.repo = repo;
        this.token = token;
        this.api = 'https://api.github.com';
    }

    async pushFile(path, content, message = 'Update vault data') {
        const url = `${this.api}/repos/${this.owner}/${this.repo}/contents/${path}`;

        // Check if file exists
        let sha = null;
        try {
            const response = await fetch(url, {
                headers: { 'Authorization': `token ${this.token}` }
            });
            if (response.ok) {
                const data = await response.json();
                sha = data.sha;
            }
        } catch(e) {}

        // Prepare content (base64)
        const base64Content = btoa(unescape(encodeURIComponent(JSON.stringify(content, null, 2))));

        const body = {
            message,
            content: base64Content,
            branch: 'main'
        };
        if (sha) body.sha = sha;

        const response = await fetch(url, {
            method: 'PUT',
            headers: {
                'Authorization': `token ${this.token}`,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(body)
        });

        return response.ok;
    }

    async pushUserProfile(userId, profile) {
        return this.pushFile(`data/vault/personality/${userId}.json`, profile, `Update profile for ${userId}`);
    }

    async pushMessage(messageRecord) {
        return this.pushFile(`data/vault/messages/${messageRecord.id}.json`, messageRecord, `Record message from ${messageRecord.userId}`);
    }

    async pushTransaction(transaction) {
        // Append to transactions.jsonl
        const url = `${this.api}/repos/${this.owner}/${this.repo}/contents/data/vault/revenue/transactions.jsonl`;

        // Get current content
        let currentContent = '';
        let sha = null;
        try {
            const response = await fetch(url, {
                headers: { 'Authorization': `token ${this.token}` }
            });
            if (response.ok) {
                const data = await response.json();
                currentContent = atob(data.content);
                sha = data.sha;
            }
        } catch(e) {}

        const newContent = currentContent + JSON.stringify(transaction) + '\n';
        const base64Content = btoa(unescape(encodeURIComponent(newContent)));

        const body = {
            message: `Record transaction from ${transaction.userId}`,
            content: base64Content,
            branch: 'main'
        };
        if (sha) body.sha = sha;

        const response = await fetch(url, {
            method: 'PUT',
            headers: {
                'Authorization': `token ${this.token}`,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(body)
        });

        return response.ok;
    }
}

export default GitHubSync;
