    <script>
        // ============================================================
        // VAULT DASHBOARD — The Gold View
        // Loads all data from localStorage and displays insights
        // ============================================================

        let vaultData = {
            users: [],
            messages: [],
            transactions: [],
            personalities: new Map()
        };

        // Load all data from localStorage
        function loadVaultData() {
            // Load users (from pantheon user data)
            const usersRaw = localStorage.getItem('pantheon_users');
            if (usersRaw) {
                const usersObj = JSON.parse(usersRaw);
                vaultData.users = Object.entries(usersObj).map(([email, data]) => ({
                    id: email,
                    email: email,
                    ...data,
                    ...loadPersonalityProfile(email)
                }));
            }

            // Load messages
            const messagesRaw = localStorage.getItem('seshat_messages');
            if (messagesRaw) {
                vaultData.messages = JSON.parse(messagesRaw);
            }

            // Load transactions
            const revenueRaw = localStorage.getItem('revenue_log');
            if (revenueRaw) {
                vaultData.transactions = JSON.parse(revenueRaw);
            }

            // Load personality profiles
            for (const user of vaultData.users) {
                const profile = loadPersonalityProfile(user.email);
                if (profile) {
                    vaultData.personalities.set(user.email, profile);
                }
            }

            updateStats();
            renderUserTable();
            renderMessageTable();
            renderTransactionTable();
            renderInsights();
            renderRevenueChart();
        }

        function loadPersonalityProfile(email) {
            const key = `personality_${email}`;
            const raw = localStorage.getItem(key);
            if (raw) {
                return JSON.parse(raw);
            }
            return null;
        }

        function updateStats() {
            const totalUsers = vaultData.users.length;
            const totalMessages = vaultData.messages.length;
            const totalRevenue = vaultData.transactions.reduce((sum, t) => sum + (t.amount || 0), 0);
            const avgLTV = totalUsers ? totalRevenue / totalUsers : 0;

            // Count unique personalities
            const personalityCount = vaultData.personalities.size;

            // Active today (last 24h)
            const today = Date.now() - 24 * 60 * 60 * 1000;
            const activeToday = vaultData.users.filter(u => (u.lastActive || 0) > today).length;

            document.getElementById('totalUsers').innerText = totalUsers;
            document.getElementById('totalMessages').innerText = totalMessages;
            document.getElementById('totalRevenue').innerHTML = `$${totalRevenue.toFixed(2)}`;
            document.getElementById('avgLTV').innerHTML = `$${avgLTV.toFixed(2)}`;
            document.getElementById('personalityCount').innerText = personalityCount;
            document.getElementById('activeToday').innerText = activeToday;
        }

        function renderUserTable() {
            const tbody = document.getElementById('userTableBody');
            if (vaultData.users.length === 0) {
                tbody.innerHTML = '<tr><td colspan="7" style="text-align: center;">No users yet. The vault awaits souls.</td></tr>';
                return;
            }

            tbody.innerHTML = vaultData.users.map(user => {
                const plt = user.plt || { profit: 0, love: 0, tax: 0 };
                const total = plt.profit + plt.love + plt.tax;
                const pltDisplay = total > 0 ? `P:${Math.round(plt.profit/total*100)}% L:${Math.round(plt.love/total*100)}% T:${Math.round(plt.tax/total*100)}%` : '—';

                return `
                    <tr onclick="showUserDetail('${user.email}')">
                        <td style="color: #ffaa66;">${user.email}</td>
                        <td>${user.archetype || 'The Seeker'}</td>
                        <td style="font-family: monospace; font-size: 10px;">${pltDisplay}</td>
                        <td>${user.messageCount || 0}</td>
                        <td>$${(user.lifetimeValue || 0).toFixed(2)}</td>
                        <td><span class="personality-tag">${user.segment || 'free'}</span></td>
                        <td>${user.lastActive ? new Date(user.lastActive).toLocaleDateString() : '—'}</td>
                    </tr>
                `;
            }).join('');
        }

        function renderMessageTable() {
            const tbody = document.getElementById('messageTableBody');
            const messages = [...vaultData.messages].reverse().slice(0, 100);

            if (messages.length === 0) {
                tbody.innerHTML = '<tr><td colspan="6" style="text-align: center;">No messages yet. The council awaits.</td></tr>';
                return;
            }

            tbody.innerHTML = messages.map(msg => {
                const emotionIcon = msg.context?.emotionalWeight > 0.7 ? '🔥' : 
                                   msg.context?.emotionalWeight > 0.5 ? '📝' : '💭';
                const topic = msg.context?.topic || 'general';
                const time = msg.context?.timestamp ? new Date(msg.context.timestamp).toLocaleString() : '—';
                const messagePreview = msg.message.length > 60 ? msg.message.substring(0, 60) + '...' : msg.message;

                return `
                    <tr>
                        <td style="color: #ffaa66;">${msg.userId || 'unknown'}</td>
                        <td>${messagePreview}</td>
                        <td>${topic}</td>
                        <td>${emotionIcon}</td>
                        <td style="color: #88ffaa;">${msg.response ? msg.response.substring(0, 40) + '...' : '—'}</td>
                        <td>${time}</td>
                    </tr>
                `;
            }).join('');
        }

        function renderTransactionTable() {
            const tbody = document.getElementById('transactionTableBody');
            const transactions = [...vaultData.transactions].reverse();

            if (transactions.length === 0) {
                tbody.innerHTML = '<tr><td colspan="4" style="text-align: center;">No transactions yet. The vault is waiting for offerings.</td></tr>';
                return;
            }

            tbody.innerHTML = transactions.map(t => {
                const date = t.timestamp ? new Date(t.timestamp).toLocaleDateString() : '—';
                return `
                    <tr>
                        <td>${t.userId || t.source || 'anonymous'}</td>
                        <td style="color: #ffaa44; font-weight: bold;">$${t.amount.toFixed(2)}</td>
                        <td>${t.type || 'credit_pack'}</td>
                        <td>${date}</td>
                    </tr>
                `;
            }).join('');
        }

        function renderInsights() {
            // Calculate dominant PLT
            let profitCount = 0, loveCount = 0, taxCount = 0;
            vaultData.users.forEach(user => {
                const plt = user.plt || { profit: 0, love: 0, tax: 0 };
                const total = plt.profit + plt.love + plt.tax;
                if (total > 0) {
                    if (plt.profit >= plt.love && plt.profit >= plt.tax) profitCount++;
                    else if (plt.love >= plt.profit && plt.love >= plt.tax) loveCount++;
                    else taxCount++;
                }
            });

            const dominant = profitCount > loveCount && profitCount > taxCount ? 'Profit Prime' :
                            loveCount > profitCount && loveCount > taxCount ? 'Love Weaver' :
                            taxCount > profitCount && taxCount > loveCount ? 'Tax Collector' : 'Balanced Council';
            document.getElementById('dominantPLT').innerHTML = dominant;

            // Hottest topic
            const topics = {};
            vaultData.messages.forEach(msg => {
                const topic = msg.context?.topic || 'general';
                topics[topic] = (topics[topic] || 0) + 1;
            });
            const hottest = Object.entries(topics).sort((a,b) => b[1] - a[1])[0];
            document.getElementById('hottestTopic').innerHTML = hottest ? `${hottest[0]} (${hottest[1]})` : '—';

            // Highest value segment
            const segments = { free: 0, low_value: 0, medium_value: 0, high_value: 0 };
            vaultData.users.forEach(user => {
                const ltv = user.lifetimeValue || 0;
                if (ltv === 0) segments.free++;
                else if (ltv < 50) segments.low_value++;
                else if (ltv < 500) segments.medium_value++;
                else segments.high_value++;
            });
            const highest = Object.entries(segments).sort((a,b) => b[1] - a[1])[0];
            document.getElementById('highestSegment').innerHTML = highest ? `${highest[0]} (${highest[1]} users)` : '—';

            // Personality distribution HTML
            const distHtml = `
                <div style="padding: 15px;">
                    <div class="revenue-bar"><div class="bar-label">Profit Prime</div><div class="bar-fill" style="width: ${(profitCount/vaultData.users.length*100)||0}%;"></div><div class="bar-value">${profitCount}</div></div>
                    <div class="revenue-bar"><div class="bar-label">Love Weaver</div><div class="bar-fill" style="width: ${(loveCount/vaultData.users.length*100)||0}%;"></div><div class="bar-value">${loveCount}</div></div>
                    <div class="revenue-bar"><div class="bar-label">Tax Collector</div><div class="bar-fill" style="width: ${(taxCount/vaultData.users.length*100)||0}%;"></div><div class="bar-value">${taxCount}</div></div>
                </div>
            `;
            document.getElementById('personalityDistribution').innerHTML = distHtml;
        }

        function renderRevenueChart() {
            // Group revenue by month
            const monthly = {};
            vaultData.transactions.forEach(t => {
                if (t.timestamp) {
                    const date = new Date(t.timestamp);
                    const month = `${date.getFullYear()}-${date.getMonth()+1}`;
                    monthly[month] = (monthly[month] || 0) + (t.amount || 0);
                }
            });

            const months = Object.keys(monthly).sort();
            const maxRevenue = Math.max(...Object.values(monthly), 1);

            const chartHtml = `
                <div style="margin-bottom: 20px;">
                    <div class="stat-label">📅 MONTHLY REVENUE</div>
                </div>
                ${months.map(month => `
                    <div class="revenue-bar">
                        <div class="bar-label">${month}</div>
                        <div class="bar-fill" style="width: ${(monthly[month]/maxRevenue*100)}%; background: linear-gradient(90deg, #ffaa44, #ff8844);"></div>
                        <div class="bar-value">$${monthly[month].toFixed(2)}</div>
                    </div>
                `).join('')}
                ${months.length === 0 ? '<div style="text-align: center; padding: 40px;">No revenue data yet. The vault awaits offerings.</div>' : ''}
            `;
            document.getElementById('revenueChart').innerHTML = chartHtml;
        }

        function showUserDetail(email) {
            const user = vaultData.users.find(u => u.email === email);
            const profile = vaultData.personalities.get(email);

            const modal = document.getElementById('userModal');
            const modalName = document.getElementById('modalUserName');
            const modalContent = document.getElementById('modalContent');

            modalName.innerHTML = user.email;

            // Get user's messages
            const userMessages = vaultData.messages.filter(m => m.userId === email).slice(-10);

            modalContent.innerHTML = `
                <div style="margin-bottom: 20px;">
                    <h3>🧬 PERSONALITY PROFILE</h3>
                    <p><strong>Archetype:</strong> ${user.archetype || 'The Seeker'}</p>
                    <p><strong>PLT Affinity:</strong> P:${Math.round((user.plt?.profit||0)*100)}% L:${Math.round((user.plt?.love||0)*100)}% T:${Math.round((user.plt?.tax||0)*100)}%</p>
                    <p><strong>Messages:</strong> ${user.messageCount || 0}</p>
