```javascript
// ============================================================
// GITHUB SYNC — Automatic Vault Backup
// Pushes all user data, messages, transactions to repository
// ============================================================

class GitHubSync {
    constructor(owner, repo, token, branch = 'main') {
        this.owner = owner;
        this.repo = repo;
        this.token = token;
        this.branch = branch;
        this.api = 'https://api.github.com';
        this.syncQueue = [];
        this.isSyncing = false;
    }

    // Check if token is configured
    isConfigured() {
        return this.token && this.token !== 'YOUR_GITHUB_TOKEN' && this.token.length > 10;
    }

    // Push a file to GitHub (creates or updates)
    async pushFile(path, content, message = 'Update vault data') {
        if (!this.isConfigured()) {
            console.warn('GitHub sync not configured — data saved locally only');
            return false;
        }

        const url = `${this.api}/repos/${this.owner}/${this.repo}/contents/${path}`;

        // Get current file SHA if exists
        let sha = null;
        try {
            const response = await fetch(url, {
                headers: { 'Authorization': `token ${this.token}` }
            });
            if (response.ok) {
                const data = await response.json();
                sha = data.sha;
            }
        } catch(e) {}

        // Prepare content (base64)
        const contentStr = typeof content === 'string' ? content : JSON.stringify(content, null, 2);
        const base64Content = btoa(unescape(encodeURIComponent(contentStr)));

        const body = {
            message,
            content: base64Content,
            branch: this.branch
        };
        if (sha) body.sha = sha;

        try {
            const response = await fetch(url, {
                method: 'PUT',
                headers: {
                    'Authorization': `token ${this.token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(body)
            });
            return response.ok;
        } catch(e) {
            console.error('GitHub sync failed:', e);
            return false;
        }
    }

    // Push user profile
    async pushUserProfile(userId, profile) {
        return this.pushFile(
            `data/vault/personality/${userId}.json`,
            profile,
            `Update profile for ${userId}`
        );
    }

    // Push a single message
    async pushMessage(messageRecord) {
        return this.pushFile(
            `data/vault/messages/${messageRecord.id}.json`,
            messageRecord,
            `Record message from ${messageRecord.userId}`
        );
    }

    // Append to transactions log (JSONL format)
    async pushTransaction(transaction) {
        const path = 'data/vault/revenue/transactions.jsonl';
        const url = `${this.api}/repos/${this.owner}/${this.repo}/contents/${path}`;

        let currentContent = '';
        let sha = null;

        try {
            const response = await fetch(url, {
                headers: { 'Authorization': `token ${this.token}` }
            });
            if (response.ok) {
                const data = await response.json();
                currentContent = atob(data.content);
                sha = data.sha;
            }
        } catch(e) {}

        const newContent = currentContent + JSON.stringify(transaction) + '\n';
        const base64Content = btoa(unescape(encodeURIComponent(newContent)));

        const body = {
            message: `Record transaction from ${transaction.userId}`,
            content: base64Content,
            branch: this.branch
        };
        if (sha) body.sha = sha;

        try {
            const response = await fetch(url, {
                method: 'PUT',
                headers: {
                    'Authorization': `token ${this.token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(body)
            });
            return response.ok;
        } catch(e) {
            console.error('Transaction sync failed:', e);
            return false;
        }
    }

    // Push user index (master list)
    async pushUserIndex(users) {
        const index = {
            updatedAt: Date.now(),
            userCount: users.length,
            users: users.map(u => ({
                id: u.id,
                email: u.email,
                archetype: u.archetype,
                segment: u.segment,
                ltv: u.lifetimeValue,
                lastActive: u.lastActive
            }))
        };
        return this.pushFile('data/vault/index.json', index, 'Update user index');
    }

    // Queue a sync operation
    queueSync(type, data) {
        this.syncQueue.push({ type, data, timestamp: Date.now() });
        this.processQueue();
    }

    async processQueue() {
        if (this.isSyncing) return;
        this.isSyncing = true;

        while (this.syncQueue.length > 0) {
            const item = this.syncQueue.shift();
            try {
                switch(item.type) {
                    case 'user':
                        await this.pushUserProfile(item.data.userId, item.data.profile);
                        break;
                    case 'message':
                        await this.pushMessage(item.data);
                        break;
                    case 'transaction':
                        await this.pushTransaction(item.data);
                        break;
                    case 'index':
                        await this.pushUserIndex(item.data);
                        break;
                }
            } catch(e) {
                console.warn('Sync failed for item, will retry later:', e);
                // Re-queue with delay
                setTimeout(() => this.queueSync(item.type, item.data), 60000);
            }
        }

        this.isSyncing = false;
    }
}

export default GitHubSync;
