            orb.castShadow = true;
            scene.add(orb);
            orbs.push(orb);
        });

        // --- Sky glow effect (simple gradient using a large sphere with alpha) ---
        const skyMat = new THREE.MeshBasicMaterial({ color: 0x331144, transparent: true, opacity: 0.2, side: THREE.BackSide });
        const skySphere = new THREE.Mesh(new THREE.SphereGeometry(40, 32, 32), skyMat);
        scene.add(skySphere);

        // --- Animation & time ---
        let time = 0;

        function animate() {
            requestAnimationFrame(animate);
            time += 0.012;

            // Rotate the ring symbols
            ringSymbols.forEach((sym, idx) => {
                const angle = (idx / ringSymbols.length) * Math.PI * 2 + time * 0.3;
                const rad = 3.2;
                sym.position.x = Math.cos(angle) * rad;
                sym.position.z = Math.sin(angle) * rad;
                sym.position.y = 0.8 + Math.sin(time * 1.5 + idx) * 0.1;
            });

            // Animate floating orbs
            orbs.forEach((orb, i) => {
                orb.position.y = 1.2 + Math.sin(time * 1.2 + i) * 0.15;
                orb.material.emissiveIntensity = 0.5 + Math.sin(time * 2 + i) * 0.2;
            });

            // Pulse the color light
            const intensity = 0.5 + Math.sin(time * 0.8) * 0.3;
            colorLight.intensity = intensity;

            // Slowly rotate particles
            particles.rotation.y += 0.0005;
            particles.rotation.x += 0.0003;

            // Gentle camera auto‑orbit (optional)
            // controls.autoRotate = false; // we keep manual control

            controls.update();
            effectComposer.render();
        }

        animate();

        // --- Resize handler ---
        window.addEventListener('resize', onWindowResize, false);
        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            effectComposer.setSize(window.innerWidth, window.innerHeight);
        }

        // --- Add a faint ground mist effect using transparent planes ---
        const mistMat = new THREE.MeshStandardMaterial({ color: 0x88aaff, emissive: 0x224466, transparent: true, opacity: 0.08, side: THREE.DoubleSide });
        const mistPlane = new THREE.Mesh(new THREE.PlaneGeometry(20, 20), mistMat);
        mistPlane.rotation.x = -Math.PI / 2;
        mistPlane.position.y = -0.4;
        scene.add(mistPlane);

