        let log = [];
        log.push(`⚔️ BATTLE: ${soulA.name} vs ${soulB.name}`);
        function addLog(msg) { log.push(msg); updateBattleLog(log); }
        function calcDamage(att, def) {
            let base = 10 + att.level;
            let advantage = 1.0;
            if (att.type === 'profit' && def.type === 'love') advantage = pltRules.profitLoveAdv;
            else if (att.type === 'love' && def.type === 'tax') advantage = pltRules.loveTaxAdv;
            else if (att.type === 'tax' && def.type === 'profit') advantage = pltRules.taxProfitAdv;
            else if (att.type === 'love' && def.type === 'profit') advantage = 0.7;
            else if (att.type === 'tax' && def.type === 'love') advantage = 0.7;
            else if (att.type === 'profit' && def.type === 'tax') advantage = 0.7;
            let dmg = base * advantage;
            if (att.skills.includes('strategize')) dmg *= 1.15;
            dmg *= (0.5 + att.energy/200);
            return Math.max(5, Math.min(45, Math.floor(dmg)));
        }
        while (hpA > 0 && hpB > 0) {
            let dmg = calcDamage(soulA, soulB);
            hpB -= dmg;
            energyA -= 5;
