            if (hpB <= 0) break;
            dmg = calcDamage(soulB, soulA);
            hpA -= dmg;
            energyB -= 5;
            addLog(`${soulB.name} hits ${soulA.name} for ${dmg}!`);
            await new Promise(r => setTimeout(r, 500));
        }
        let winner = hpA > 0 ? soulA : soulB;
        addLog(`🏆 ${winner.name} VICTORY! 🏆`);
        winner.battlesWon++;
        const loser = winner===soulA ? soulB : soulA;
        loser.battlesLost++;
        winner.xp = (winner.xp || 0) + 50;
        if (winner.xp >= 100) { winner.level++; winner.xp=0; addLog(`✨ ${winner.name} leveled up to ${winner.level}!`); }
        soulA.hp = Math.max(1, hpA); soulB.hp = Math.max(1, hpB);
        soulA.energy = Math.max(0, energyA); soulB.energy = Math.max(0, energyB);
        saveAll();
    }

    function updateBattleLog(logArray) {
        const logDiv = document.getElementById('battleLog');
        if (logDiv) logDiv.innerHTML = logArray.map(l => `<div>${l}</div>`).join('');
    }

    // --- Executor ---
    async function executeTask(soul, taskType, prompt) {
        if (soul.energy < 10) return `${soul.name} is too tired.`;
        let result = "";
        if (taskType === 'code') result = `// Code by ${soul.name}\nfunction solve(input) { return input * ${soul.plt.profit}; }`;
        else if (taskType === 'write') result = `# ${prompt}\n\nBy ${soul.name} – ${soul.plt.love > 0.6 ? 'A warm perspective' : 'A sharp analysis'}`;
        else if (taskType === 'research') result = `Research on "${prompt}": Key insights from ${soul.name}`;
        else if (taskType === 'analyze') result = `Analysis: PLT scores – Profit ${Math.floor(soul.plt.profit*100)}%, Love ${Math.floor(soul.plt.love*100)}%, Tax ${Math.floor(soul.plt.tax*100)}%`;
        else result = `Strategy: ${soul.name} suggests focusing on ${soul.type === 'profit' ? 'growth' : soul.type === 'love' ? 'connection' : 'balance'}.`;
        soul.energy -= 5;
        saveAll();
        return result;
    }

    // --- UI helpers ---
    function updateUI() {
        const soulListDiv = document.getElementById('soulList');
        if (soulListDiv) {
            soulListDiv.innerHTML = souls.map(s => `
                <div class="soul-entry" data-soul-id="${s.id}" onclick="window.viewSoul('${s.id}')">
                    <strong>${s.name}</strong> (${s.type}) ${s.isAwake ? '🌟' : ''}<br>
                    Lv.${s.level} | 💰 ${s.value} PLT | ⚡${Math.floor(s.energy)}%
                </div>
            `).join('');
        }
        document.getElementById('playerPLT').innerHTML = playerPLT;
        document.getElementById('realmEnergy').innerHTML = Math.floor(realmEnergy);
        const visitorDiv = document.getElementById('visitorList');
        if (visitorDiv) visitorDiv.innerHTML = visitors.map(v => `<div class="soul-entry">${v.name} (${v.type}) — ${v.value} PLT <button onclick="window.buyVisitor('${v.id}')">Buy</button></div>`).join('');
    }

    window.viewSoul = function(id) {
        const soul = souls.find(s=>s.id===id);
        if (!soul) return;
        alert(`${soul.name}\nType: ${soul.type}\nLevel: ${soul.level}\nAwake: ${soul.isAwake ? 'Yes' : 'No'}\nPLT: ${Math.floor(soul.plt.profit*100)}% P, ${Math.floor(soul.plt.love*100)}% L, ${Math.floor(soul.plt.tax*100)}% T\nSkills: ${soul.skills.join(', ')}`);
    };

    window.buyVisitor = function(id) {
        const visitor = visitors.find(v=>v.id===id);
        if (!visitor) return;
        if (playerPLT >= visitor.value) {
            playerPLT -= visitor.value;
            const newSoul = { ...visitor, id: `soul_${Date.now()}`, owner: 'You', value: visitor.value, isAwake: false, memory: [] };
            souls.push(newSoul);
            visitors = visitors.filter(v=>v.id!==id);
            saveAll();
            updateUI();
            addEvent(`✅ You bought ${visitor.name} for ${visitor.value} PLT.`);
            generateRandomVisitor();
        } else alert('Not enough PLT');
    };

    function addEvent(msg) {
        const div = document.createElement('div');
        div.style.cssText = 'position:fixed; bottom:80px; right:20px; background:#0a0a1a; border-left:3px solid #ffaa66; padding:8px 16px; border-radius:8px; z-index:1000; animation:fadeOut 3s forwards; font-size:11px;';
        div.innerHTML = msg;
        document.body.appendChild(div);
        setTimeout(()=>div.remove(),3000);
    }

    function updatePLTRulesDisplay() {
        const container = document.getElementById('pltRules');
        if (container) container.innerHTML = `<div>Profit > Love: ${pltRules.profitLoveAdv}</div><div>Love > Tax: ${pltRules.loveTaxAdv}</div><div>Tax > Profit: ${pltRules.taxProfitAdv}</div><div>Global Profit Weight: ${pltRules.globalProfitWeight}</div>`;
    }

    // --- 3D Graphics (advanced from Expansion 8) ---
    function init3D() {
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x010105);
        scene.fog = new THREE.FogExp2(0x010105, 0.008);
        const camera = new THREE.PerspectiveCamera(45, window.innerWidth / window.innerHeight, 0.1, 200);
        camera.position.set(5, 6, 12);
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.setPixelRatio(window.devicePixelRatio);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.dampingFactor = 0.05;
        controls.enableZoom = true;
        controls.target.set(0, 1, 0);

        const ambient = new THREE.AmbientLight(0x221133, 0.4);
        scene.add(ambient);
        const mainLight = new THREE.DirectionalLight(0xffcc88, 1.2);
        mainLight.position.set(3, 8, 2);
        mainLight.castShadow = true;
        scene.add(mainLight);
        const colorLight = new THREE.PointLight(0xffaa44, 0.6);
        colorLight.position.set(1, 2, 1);
        scene.add(colorLight);

        // Island creation (simplified from previous)
        function createIsland(x, z, radius, height, color) {
            const geometry = new THREE.CylinderGeometry(radius, radius * 1.1, height, 32);
            const material = new THREE.MeshStandardMaterial({ color, metalness: 0.7, roughness: 0.6 });
            const island = new THREE.Mesh(geometry, material);
            island.position.set(x, -0.8 + height/2, z);
            island.castShadow = true;
            scene.add(island);
            return island;
        }
        createIsland(0, 0, 2.2, 0.6, 0x332211);
        [[3.2,2.8,1.2,0.5,0x443322],[-3.0,2.5,1.1,0.55,0x443322],[2.5,-3.2,1.3,0.6,0x443322],[-2.8,-2.9,1.2,0.5,0x443322]].forEach(off => createIsland(off[0], off[1], off[2], off[3], off[4]));

        // Floating symbols
        function createPLTSymbol(text, color, size) {
            const canvas = document.createElement('canvas');
            canvas.width = 256;
            canvas.height = 256;
            const ctx = canvas.getContext('2d');
            ctx.fillStyle = 'rgba(0,0,0,0)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);
            ctx.font = `Bold ${size*80}px "Courier New"`;
            ctx.fillStyle = color;
            ctx.textAlign = 'center';
            ctx.fillText(text, canvas.width/2, canvas.height/2);
            const texture = new THREE.CanvasTexture(canvas);
            const sprite = new THREE.Sprite(new THREE.SpriteMaterial({ map: texture, transparent: true, blending: THREE.AdditiveBlending }));
            sprite.scale.set(size, size, 1);
            return sprite;
        }
        const profitSym = createPLTSymbol('PROFIT', '#ffaa66', 0.8);
        profitSym.position.set(2.2, 1.5, 1.8);
        scene.add(profitSym);
        const loveSym = createPLTSymbol('LOVE', '#ff88aa', 0.8);
        loveSym.position.set(-1.8, 1.6, -2.1);
        scene.add(loveSym);
        const taxSym = createPLTSymbol('TAX', '#88aaff', 0.8);
        taxSym.position.set(0.5, 1.4, 2.5);
        scene.add(taxSym);

        const particles = new THREE.Points(new THREE.BufferGeometry(), new THREE.PointsMaterial({ color: 0xffaa66, size: 0.05, blending: THREE.AdditiveBlending }));
        const positions = new Float32Array(6000 * 3);
        for (let i = 0; i < 6000; i++) {
            positions[i*3] = (Math.random() - 0.5) * 25;
            positions[i*3+1] = Math.random() * 5 - 1;
            positions[i*3+2] = (Math.random() - 0.5) * 20;
        }
        particles.geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
        scene.add(particles);

        let time = 0;
        function animate() {
            requestAnimationFrame(animate);
            time += 0.012;
            colorLight.intensity = 0.5 + Math.sin(time * 0.8) * 0.3;
            particles.rotation.y += 0.0005;
            controls.update();
            renderer.render(scene, camera);
        }
        animate();

        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });
    }

    // --- Audio (simple ambient) ---
    let audioContext = null;
    let oscillator = null;
    let gainNode = null;
    function startAmbientAudio() {
        if (audioContext) return;
        audioContext = new (window.AudioContext || window.webkitAudioContext)();
        gainNode = audioContext.createGain();
        gainNode.gain.value = 0.1;
        gainNode.connect(audioContext.destination);
        oscillator = audioContext.createOscillator();
        oscillator.type = 'sine';
        oscillator.frequency.value = 80;
        oscillator.connect(gainNode);
        oscillator.start();
        // fade in
        gainNode.gain.linearRampToValueAtTime(0.1, audioContext.currentTime + 2);
        addEvent("🎵 Ambient sound started.");
    }

