<script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
    import { EffectComposer } from 'three/addons/postprocessing/EffectComposer.js';
    import { RenderPass } from 'three/addons/postprocessing/RenderPass.js';
    import { UnrealBloomPass } from 'three/addons/postprocessing/UnrealBloomPass.js';

    // ============================================================
    // SOULVERSE VOXEL – FULL BLOCK EDITING
    // ============================================================

    // --- Constants ---
    const WORLD_SIZE = 32;          // chunks per side (radius)
    const CHUNK_SIZE = 16;          // blocks per chunk dimension
    const BLOCK_SIZE = 1;
    const RENDER_DISTANCE = 4;      // chunks radius

    // --- Block types ---
    const BLOCK_TYPES = {
        AIR: 0,
        DIRT: 1,
        GRASS: 2,
        STONE: 3,
        PROFIT_GOLD: 4,
        LOVE_PINK: 5,
        TAX_BLUE: 6
    };
    const BLOCK_COLORS = {
        [BLOCK_TYPES.DIRT]: 0x8B5A2B,
        [BLOCK_TYPES.GRASS]: 0x7CB518,
        [BLOCK_TYPES.STONE]: 0x808080,
        [BLOCK_TYPES.PROFIT_GOLD]: 0xffaa44,
        [BLOCK_TYPES.LOVE_PINK]: 0xff88aa,
        [BLOCK_TYPES.TAX_BLUE]: 0x88aaff
    };
    const BLOCK_NAMES = {
        [BLOCK_TYPES.AIR]: "Air",
        [BLOCK_TYPES.DIRT]: "Dirt",
        [BLOCK_TYPES.GRASS]: "Grass",
        [BLOCK_TYPES.STONE]: "Stone",
        [BLOCK_TYPES.PROFIT_GOLD]: "Profit Gold",
        [BLOCK_TYPES.LOVE_PINK]: "Love Pink",
        [BLOCK_TYPES.TAX_BLUE]: "Tax Blue"
    };

    // --- Chunk data storage ---
    // chunkData map: key "x,z" -> 3D array of block types [y][z][x] (or flat)
    let chunkData = new Map();

    // --- Game state ---
    let scene, camera, renderer, composer, controls;
    let chunks = new Map(); // map chunk key -> Three.js mesh
    let player = { x: 0, y: 10, z: 0, velocity: { x:0, y:0, z:0 }, onGround: true };
    let keys = { w:0, s:0, a:0, d:0, space:0, shift:0 };
    let mouse = { x:0, y:0, locked: false };
    let selectedBlock = BLOCK_TYPES.GRASS;
    let fps = 0;
    let frameCount = 0;
    let lastTime = performance.now();

    // PLT resources
    let plt = { profit: 100, love: 100, tax: 100, realm: 100 };
    let souls = [];

    // Quality settings
    let quality = 'medium';
    let postEnabled = true;

    // Helper: get block in chunk
    function getBlock(cx, cz, x, y, z) {
        const key = `${cx},${cz}`;
        let data = chunkData.get(key);
        if (!data) return BLOCK_TYPES.AIR;
        // data is a flat array of size CHUNK_SIZE^3, index = y*CHUNK_SIZE*CHUNK_SIZE + z*CHUNK_SIZE + x
        return data[y * CHUNK_SIZE * CHUNK_SIZE + z * CHUNK_SIZE + x];
    }

    function setBlock(cx, cz, x, y, z, type) {
        const key = `${cx},${cz}`;
        let data = chunkData.get(key);
        if (!data) {
            // Generate chunk data if missing
            data = generateChunkData(cx, cz);
            chunkData.set(key, data);
        }
        const idx = y * CHUNK_SIZE * CHUNK_SIZE + z * CHUNK_SIZE + x;
        data[idx] = type;
        // rebuild mesh for this chunk
        rebuildChunkMesh(cx, cz);
    }

    // Generate chunk data (initial terrain)
    function generateChunkData(cx, cz) {
        const blocks = new Array(CHUNK_SIZE * CHUNK_SIZE * CHUNK_SIZE).fill(BLOCK_TYPES.AIR);
        for (let x = 0; x < CHUNK_SIZE; x++) {
            for (let z = 0; z < CHUNK_SIZE; z++) {
                const worldX = cx * CHUNK_SIZE + x;
                const worldZ = cz * CHUNK_SIZE + z;
                // Perlin-like height
                const height = Math.floor(
                    Math.sin(worldX * 0.1) * Math.cos(worldZ * 0.1) * 3 +
                    5 + Math.sin(worldX * 0.05) * 2
                );
                for (let y = 0; y <= height; y++) {
                    let type = BLOCK_TYPES.DIRT;
                    if (y === height) type = BLOCK_TYPES.GRASS;
                    else if (y > height-3) type = BLOCK_TYPES.DIRT;
                    else type = BLOCK_TYPES.STONE;
                    const idx = y * CHUNK_SIZE * CHUNK_SIZE + z * CHUNK_SIZE + x;
                    blocks[idx] = type;
                }
            }
        }
        return blocks;
    }

    // Build a mesh from chunk data
    function buildChunkMesh(cx, cz) {
        const blocks = chunkData.get(`${cx},${cz}`);
        if (!blocks) return null;

        const geometry = new THREE.BufferGeometry();
        const positions = [];
        const normals = [];
        const indices = [];

        function addCube(x, y, z, type) {
            // Vertex positions for a cube at (x,y,z)
            const v0 = new THREE.Vector3(x, y, z);
            const v1 = new THREE.Vector3(x+1, y, z);
            const v2 = new THREE.Vector3(x+1, y+1, z);
            const v3 = new THREE.Vector3(x, y+1, z);
            const v4 = new THREE.Vector3(x, y, z+1);
            const v5 = new THREE.Vector3(x+1, y, z+1);
            const v6 = new THREE.Vector3(x+1, y+1, z+1);
            const v7 = new THREE.Vector3(x, y+1, z+1);

            const faces = [
                [v0, v1, v2, v3], // -z
                [v4, v5, v6, v7], // +z
                [v0, v1, v5, v4], // -y
                [v3, v2, v6, v7], // +y
                [v0, v3, v7, v4], // -x
                [v1, v2, v6, v5]  // +x
            ];

            faces.forEach(face => {
                const a = positions.length/3;
                face.forEach(v => { positions.push(v.x, v.y, v.z); normals.push(0,0,0); });
                indices.push(a, a+1, a+2, a+2, a+3, a);
            });
        }

        for (let x = 0; x < CHUNK_SIZE; x++) {
            for (let z = 0; z < CHUNK_SIZE; z++) {
                for (let y = 0; y < CHUNK_SIZE; y++) {
                    const idx = y * CHUNK_SIZE * CHUNK_SIZE + z * CHUNK_SIZE + x;
                    const type = blocks[idx];
                    if (type === BLOCK_TYPES.AIR) continue;
                    // Simple culling: skip if all six neighbors are solid? Not implemented for simplicity
                    addCube(x, y, z, type);
                }
            }
        }

        geometry.setAttribute('position', new THREE.BufferAttribute(new Float32Array(positions), 3));
        geometry.setAttribute('normal', new THREE.BufferAttribute(new Float32Array(normals), 3));
        geometry.setIndex(indices);
        geometry.computeVertexNormals();

        const material = new THREE.MeshStandardMaterial({ vertexColors: false, color: 0xffffff, roughness: 0.7, metalness: 0.1 });
        const mesh = new THREE.Mesh(geometry, material);
        mesh.position.set(cx * CHUNK_SIZE, 0, cz * CHUNK_SIZE);
        return mesh;
    }

    function rebuildChunkMesh(cx, cz) {
        const key = `${cx},${cz}`;
        const oldMesh = chunks.get(key);
        if (oldMesh) scene.remove(oldMesh);
        const newMesh = buildChunkMesh(cx, cz);
        if (newMesh) {
            scene.add(newMesh);
            chunks.set(key, newMesh);
        } else {
            chunks.delete(key);
        }
    }

    // Update chunks around player
    function updateChunks() {
        const cx = Math.floor(player.x / CHUNK_SIZE);
        const cz = Math.floor(player.z / CHUNK_SIZE);
        const toLoad = [];
        for (let dx = -RENDER_DISTANCE; dx <= RENDER_DISTANCE; dx++) {
            for (let dz = -RENDER_DISTANCE; dz <= RENDER_DISTANCE; dz++) {
                const key = `${cx+dx},${cz+dz}`;
                if (!chunks.has(key) && !chunkData.has(key)) {
                    toLoad.push([cx+dx, cz+dz]);
                }
            }
        }
        // Generate chunk data for missing
        for (let [cx, cz] of toLoad) {
            const data = generateChunkData(cx, cz);
            chunkData.set(`${cx},${cz}`, data);
            rebuildChunkMesh(cx, cz);
        }
        // Also ensure chunks that have data but no mesh get built
        for (let [key, data] of chunkData) {
            if (!chunks.has(key)) {
                const [cx, cz] = key.split(',').map(Number);
                rebuildChunkMesh(cx, cz);
            }
        }
        // Unload far chunks
        for (let [key, mesh] of chunks) {
            const [cx, cz] = key.split(',').map(Number);
            if (Math.abs(cx - Math.floor(player.x/CHUNK_SIZE)) > RENDER_DISTANCE+1 ||
                Math.abs(cz - Math.floor(player.z/CHUNK_SIZE)) > RENDER_DISTANCE+1) {
                scene.remove(mesh);
                chunks.delete(key);
                // keep chunkData for later
            }
        }
        document.getElementById('chunkCount').innerText = chunks.size;
    }

    // --- Player movement ---
    function handleInput(delta) {
        const speed = keys.shift ? 8 : 4;
        const move = { x: 0, z: 0 };
        if (keys.w) move.z -= 1;
        if (keys.s) move.z += 1;
        if (keys.a) move.x -= 1;
        if (keys.d) move.x += 1;
        move.x *= speed * delta;
        move.z *= speed * delta;
        player.x += move.x;
        player.z += move.z;

        // Jump/gravity
        if (keys.space && player.onGround) {
            player.velocity.y = 5;
            player.onGround = false;
        }
        player.velocity.y -= 15 * delta;
        player.y += player.velocity.y * delta;
        if (player.y <= 10) {
            player.y = 10;
            player.velocity.y = 0;
            player.onGround = true;
        }
        document.getElementById('posX').innerText = player.x.toFixed(1);
        document.getElementById('posY').innerText = player.y.toFixed(1);
        document.getElementById('posZ').innerText = player.z.toFixed(1);
    }

    // --- Block interaction (break/place) with PLT cost ---
    let raycaster = new THREE.Raycaster();
    function handleBlockInteraction() {
        if (!mouse.locked) return;
        const direction = new THREE.Vector3(0,0,-1).applyQuaternion(camera.quaternion);
        raycaster.set(camera.position, direction);
        const intersects = raycaster.intersectObjects(Array.from(chunks.values()));
        if (intersects.length === 0) return;
        const hit = intersects[0];
        const point = hit.point;
        const normal = hit.face.normal;
        // Determine block position (the block that was hit)
        let blockPos = {
            x: Math.floor(point.x - normal.x * 0.5),
            y: Math.floor(point.y - normal.y * 0.5),
            z: Math.floor(point.z - normal.z * 0.5)
        };
        // Ensure within chunk bounds
        const cx = Math.floor(blockPos.x / CHUNK_SIZE);
        const cz = Math.floor(blockPos.z / CHUNK_SIZE);
        const lx = blockPos.x - cx * CHUNK_SIZE;
        const ly = blockPos.y;
        const lz = blockPos.z - cz * CHUNK_SIZE;
        if (ly < 0 || ly >= CHUNK_SIZE) return;

        // Break block
        if (window.breakRequest) {
            const type = getBlock(cx, cz, lx, ly, lz);
            if (type !== BLOCK_TYPES.AIR) {
                // Gain resources based on block type
                if (type === BLOCK_TYPES.PROFIT_GOLD) plt.profit = Math.min(100, plt.profit + 2);
                if (type === BLOCK_TYPES.LOVE_PINK) plt.love = Math.min(100, plt.love + 2);
                if (type === BLOCK_TYPES.TAX_BLUE) plt.tax = Math.min(100, plt.tax + 2);
                setBlock(cx, cz, lx, ly, lz, BLOCK_TYPES.AIR);
            }
            window.breakRequest = false;
        }
        // Place block
        if (window.placeRequest) {
            // Determine adjacent block position (where to place)
            let placePos = {
                x: Math.floor(point.x + normal.x * 0.5),
                y: Math.floor(point.y + normal.y * 0.5),
                z: Math.floor(point.z + normal.z * 0.5)
            };
            const pcx = Math.floor(placePos.x / CHUNK_SIZE);
            const pcz = Math.floor(placePos.z / CHUNK_SIZE);
            const plx = placePos.x - pcx * CHUNK_SIZE;
            const ply = placePos.y;
            const plz = placePos.z - pcz * CHUNK_SIZE;
            if (ply >= 0 && ply < CHUNK_SIZE && getBlock(pcx, pcz, plx, ply, plz) === BLOCK_TYPES.AIR) {
                // Check PLT cost for special blocks
                let cost = 0;
                if (selectedBlock === BLOCK_TYPES.PROFIT_GOLD) cost = 5;
                if (selectedBlock === BLOCK_TYPES.LOVE_PINK) cost = 5;
                if (selectedBlock === BLOCK_TYPES.TAX_BLUE) cost = 5;
                if (cost > 0) {
                    if (selectedBlock === BLOCK_TYPES.PROFIT_GOLD && plt.profit < cost) return;
                    if (selectedBlock === BLOCK_TYPES.LOVE_PINK && plt.love < cost) return;
                    if (selectedBlock === BLOCK_TYPES.TAX_BLUE && plt.tax < cost) return;
                    if (selectedBlock === BLOCK_TYPES.PROFIT_GOLD) plt.profit -= cost;
                    if (selectedBlock === BLOCK_TYPES.LOVE_PINK) plt.love -= cost;
                    if (selectedBlock === BLOCK_TYPES.TAX_BLUE) plt.tax -= cost;
                }
                setBlock(pcx, pcz, plx, ply, plz, selectedBlock);
            }
            window.placeRequest = false;
        }
    }

    // --- UI Updates ---
    function updateUI() {
        document.getElementById('profitValue').innerText = Math.floor(plt.profit);
        document.getElementById('profitFill').style.width = (plt.profit/100)*100 + '%';
        document.getElementById('loveValue').innerText = Math.floor(plt.love);
        document.getElementById('loveFill').style.width = (plt.love/100)*100 + '%';
        document.getElementById('taxValue').innerText = Math.floor(plt.tax);
        document.getElementById('taxFill').style.width = (plt.tax/100)*100 + '%';
        document.getElementById('realmValue').innerText = Math.floor(plt.realm);
        document.getElementById('realmFill').style.width = (plt.realm/100)*100 + '%';

        const soulListDiv = document.getElementById('soulList');
        if (souls.length === 0) soulListDiv.innerText = 'None';
        else soulListDiv.innerHTML = souls.map(s => `<div>${s.name} (${s.type})</div>`).join('');
    }

    // --- FPS counter ---
    function updateFPS() {
        frameCount++;
        const now = performance.now();
        if (now - lastTime >= 1000) {
            fps = frameCount;
            document.getElementById('fps').innerText = fps;
            frameCount = 0;
            lastTime = now;
        }
    }

    // --- Quality settings ---
    function setQuality(level) {
        quality = level;
        if (level === 'low') {
            renderer.setPixelRatio(1);
            if (composer) composer.passes[1].strength = 0.3;
            postEnabled = false;
        } else if (level === 'medium') {
            renderer.setPixelRatio(window.devicePixelRatio);
            if (composer) composer.passes[1].strength = 0.6;
            postEnabled = true;
        } else if (level === 'high') {
            renderer.setPixelRatio(window.devicePixelRatio);
            if (composer) composer.passes[1].strength = 1.0;
            postEnabled = true;
        }
    }

    // --- Soul forging ---
    function forgeSoul() {
        const profit = document.getElementById('profitSlider').value/100;
        const love = document.getElementById('loveSlider').value/100;
        const tax = document.getElementById('taxSlider').value/100;
        const name = prompt("Soul name:", "New Soul");
        if (!name) return;
        const type = profit > love && profit > tax ? 'profit' : (love > profit && love > tax ? 'love' : 'tax');
        const newSoul = { id: Date.now(), name, type, plt: { profit, love, tax }, energy: 100 };
        souls.push(newSoul);
        updateUI();
        alert(`Soul "${name}" forged! It will now influence the world.`);
    }

    function syncSoulverse() {
        const saved = localStorage.getItem('soulforge_souls');
        if (saved) {
            souls = JSON.parse(saved);
            updateUI();
            alert(`Synced ${souls.length} souls from Soulverse.`);
        } else {
            alert("No souls found in Soulverse storage. Forge some first in the main Soulverse.");
        }
    }

    // --- Animation loop ---
    let lastFrame = performance.now();
    function animate() {
        const now = performance.now();
        let delta = Math.min(0.033, (now - lastFrame) / 1000);
        lastFrame = now;

        handleInput(delta);
        handleBlockInteraction();

        camera.position.x = player.x;
        camera.position.y = player.y + 1.6;
        camera.position.z = player.z;
        controls.target.set(player.x, player.y, player.z);

        updateChunks();
        updateFPS();

        // Regenerate PLT slowly
        plt.profit = Math.min(100, plt.profit + 0.5 * delta);
        plt.love = Math.min(100, plt.love + 0.5 * delta);
        plt.tax = Math.min(100, plt.tax + 0.5 * delta);
        plt.realm = Math.min(100, plt.realm + 0.2 * delta);
        updateUI();

        if (postEnabled) composer.render();
        else renderer.render(scene, camera);
        requestAnimationFrame(animate);
    }

    // --- Setup Three.js ---
    function init() {
        scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB);
        scene.fog = new THREE.FogExp2(0x87CEEB, 0.008);

        camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(0, 2, 5);
        controls = new OrbitControls(camera, document.body);
        controls.enableZoom = false;
        controls.enablePan = false;
        controls.mouseButtons = { LEFT: THREE.MOUSE.ROTATE, RIGHT: THREE.MOUSE.PAN };

        renderer = new THREE.WebGLRenderer({ canvas: document.getElementById('gameCanvas'), antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;

        const renderScene = new RenderPass(scene, camera);
        const bloomPass = new UnrealBloomPass(new THREE.Vector2(window.innerWidth, window.innerHeight), 0.6, 0.3, 0.85);
        composer = new EffectComposer(renderer);
        composer.addPass(renderScene);
        composer.addPass(bloomPass);

        const ambient = new THREE.AmbientLight(0x404040);
        scene.add(ambient);
        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(1, 2, 1);
        dirLight.castShadow = true;
        scene.add(dirLight);
        const fillLight = new THREE.PointLight(0xccaa88, 0.5);
        fillLight.position.set(0, 5, 0);
        scene.add(fillLight);

        // Input events
        window.addEventListener('keydown', (e) => {
            switch(e.code) {
                case 'KeyW': keys.w = 1; break;
                case 'KeyS': keys.s = 1; break;
                case 'KeyA': keys.a = 1; break;
                case 'KeyD': keys.d = 1; break;
                case 'Space': keys.space = 1; e.preventDefault(); break;
                case 'ShiftLeft': keys.shift = 1; break;
                case 'Digit1': selectedBlock = BLOCK_TYPES.GRASS; break;
                case 'Digit2': selectedBlock = BLOCK_TYPES.STONE; break;
                case 'Digit3': selectedBlock = BLOCK_TYPES.PROFIT_GOLD; break;
                case 'Digit4': selectedBlock = BLOCK_TYPES.LOVE_PINK; break;
                case 'Digit5': selectedBlock = BLOCK_TYPES.TAX_BLUE; break;
            }
        });
        window.addEventListener('keyup', (e) => {
            switch(e.code) {
                case 'KeyW': keys.w = 0; break;
                case 'KeyS': keys.s = 0; break;
                case 'KeyA': keys.a = 0; break;
                case 'KeyD': keys.d = 0; break;
                case 'Space': keys.space = 0; break;
                case 'ShiftLeft': keys.shift = 0; break;
            }
        });
        const canvasEl = document.getElementById('gameCanvas');
        canvasEl.addEventListener('click', () => canvasEl.requestPointerLock());
        document.addEventListener('pointerlockchange', () => {
            mouse.locked = document.pointerLockElement === canvasEl;
            if (mouse.locked) {
                document.body.addEventListener('mousemove', onMouseMove);
            } else {
                document.body.removeEventListener('mousemove', onMouseMove);
            }
        });
        function onMouseMove(e) {
            if (!mouse.locked) return;
            const dx = e.movementX * 0.002;
            const dy = e.movementY * 0.002;
            camera.rotation.order = 'YXZ';
            camera.rotation.y -= dx;
            camera.rotation.x -= dy;
            if (camera.rotation.x > Math.PI/2) camera.rotation.x = Math.PI/2;
            if (camera.rotation.x < -Math.PI/2) camera.rotation.x = -Math.PI/2;
        }
        window.addEventListener('mousedown', (e) => {
            if (e.button === 0) window.breakRequest = true;
            if (e.button === 2) { window.placeRequest = true; e.preventDefault(); }
        });
        window.addEventListener('contextmenu', (e) => e.preventDefault());

        document.getElementById('forgeBtn').addEventListener('click', forgeSoul);
        document.getElementById('syncSoulsBtn').addEventListener('click', syncSoulverse);
        document.getElementById('qualitySelect').addEventListener('change', (e) => setQuality(e.target.value));
        setQuality('medium');

        function updateSliders() {
            document.getElementById('profitVal').innerText = document.getElementById('profitSlider').value + '%';
            document.getElementById('loveVal').innerText = document.getElementById('loveSlider').value + '%';
            document.getElementById('taxVal').innerText = document.getElementById('taxSlider').value + '%';
        }
        document.getElementById('profitSlider').addEventListener('input', updateSliders);
        document.getElementById('loveSlider').addEventListener('input', updateSliders);
        document.getElementById('taxSlider').addEventListener('input', updateSliders);
        updateSliders();

        // Initial chunks
        updateChunks();

        animate();
    }

    init();
</script>
</body>
</html>
