            if(x0>=y0){if(y0>=z0){i1=1;j1=0;k1=0;i2=1;j2=1;k2=0;}else if(x0>=z0){i1=1;j1=0;k1=0;i2=1;j2=0;k2=1;}else{i1=0;j1=0;k1=1;i2=1;j2=0;k2=1;}}
            else{if(y0<z0){i1=0;j1=0;k1=1;i2=0;j2=1;k2=1;}else if(x0<z0){i1=0;j1=1;k1=0;i2=0;j2=1;k2=1;}else{i1=0;j1=1;k1=0;i2=1;j2=1;k2=0;}}
            let x1=x0-i1+1/6; let y1=y0-j1+1/6; let z1=z0-k1+1/6;
            let x2=x0-i2+2/6; let y2=y0-j2+2/6; let z2=z0-k2+2/6;
            let x3=x0-1; let y3=y0-1; let z3=z0-1;
            let ii=i&255; let jj=j&255; let kk=k&255;
            let gi0=perm[ii+perm[jj+perm[kk]]]%12; let gi1=perm[ii+i1+perm[jj+j1+perm[kk+k1]]]%12;
            let gi2=perm[ii+i2+perm[jj+j2+perm[kk+k2]]]%12; let gi3=perm[ii+1+perm[jj+1+perm[kk+1]]]%12;
            let t0=0.6-x0*x0-y0*y0-z0*z0; if(t0>0){t0*=t0; n0=t0*t0*dot(grad3[gi0],x0,y0,z0);}
            let t1=0.6-x1*x1-y1*y1-z1*z1; if(t1>0){t1*=t1; n1=t1*t1*dot(grad3[gi1],x1,y1,z1);}
            let t2=0.6-x2*x2-y2*y2-z2*z2; if(t2>0){t2*=t2; n2=t2*t2*dot(grad3[gi2],x2,y2,z2);}
            let t3=0.6-x3*x3-y3*y3-z3*z3; if(t3>0){t3*=t3; n3=t3*t3*dot(grad3[gi3],x3,y3,z3);}
            return 32*(n0+n1+n2+n3);
        };
    })();

    // --- Terrain generation with biomes (PLT influence) ---
    function getBlockType(wx, wy, wz) {
        const h = 12 + noise(wx*0.05, 0, wz*0.05)*5 + Math.sin(wx*0.2)*Math.cos(wz*0.2)*2;
        if (wy > Math.floor(h)) return BLOCK_TYPES.AIR;
        const biome = noise(wx*0.02, wz*0.02, 0);
        let type = BLOCK_TYPES.DIRT;
        if (wy === Math.floor(h)) {
            if (biome > 0.3) type = BLOCK_TYPES.PROFIT;
            else if (biome < -0.3) type = BLOCK_TYPES.LOVE;
            else type = BLOCK_TYPES.GRASS;
        } else if (wy > h-3) type = BLOCK_TYPES.DIRT;
        else type = BLOCK_TYPES.STONE;
        return type;
    }

    function generateChunk(cx, cz) {
        const blocks = new Array(CHUNK_SIZE*CHUNK_SIZE*CHUNK_SIZE).fill(0);
        for (let x=0;x<CHUNK_SIZE;x++) for (let z=0;z<CHUNK_SIZE;z++) {
            const wx = cx*CHUNK_SIZE + x, wz = cz*CHUNK_SIZE + z;
            for (let y=0;y<CHUNK_SIZE;y++) {
                const wy = y;
                const type = getBlockType(wx, wy, wz);
                if (type !== BLOCK_TYPES.AIR)
                    blocks[y*CHUNK_SIZE*CHUNK_SIZE + z*CHUNK_SIZE + x] = type;
            }
        }
        return blocks;
    }

    // --- Mesh building with vertex colors + emissive (for bloom) ---
    function buildChunkMesh(cx, cz) {
        const blocks = chunkData.get(`${cx},${cz}`);
        if (!blocks) return null;
        const geom = new THREE.BufferGeometry();
        const positions = [], colors = [], indices = [];
        const addCube = (x,y,z,type) => {
            const v = (a,b,c) => new THREE.Vector3(x+a, y+b, z+c);
            const col = new THREE.Color(BLOCK_COLORS[type]);
            const emissive = BLOCK_EMISSIVE[type] !== 0;
            const face = (a,b,c,d) => {
                const start = positions.length/3;
                [a,b,c,d].forEach(p => { positions.push(p.x,p.y,p.z); colors.push(col.r,col.g,col.b); });
                indices.push(start,start+1,start+2, start+2,start+3,start);
            };
            face(v(0,0,0), v(1,0,0), v(1,1,0), v(0,1,0));
            face(v(0,0,1), v(1,0,1), v(1,1,1), v(0,1,1));
            face(v(0,0,0), v(1,0,0), v(1,0,1), v(0,0,1));
            face(v(0,1,0), v(1,1,0), v(1,1,1), v(0,1,1));
            face(v(0,0,0), v(0,1,0), v(0,1,1), v(0,0,1));
            face(v(1,0,0), v(1,1,0), v(1,1,1), v(1,0,1));
        };
        for (let x=0;x<CHUNK_SIZE;x++) for (let z=0;z<CHUNK_SIZE;z++) for (let y=0;y<CHUNK_SIZE;y++) {
            const idx = y*CHUNK_SIZE*CHUNK_SIZE + z*CHUNK_SIZE + x;
            const type = blocks[idx];
            if (type !== BLOCK_TYPES.AIR) addCube(x, y, z, type);
        }
        geom.setAttribute('position', new THREE.BufferAttribute(new Float32Array(positions), 3));
        geom.setAttribute('color', new THREE.BufferAttribute(new Float32Array(colors), 3));
        geom.setIndex(indices);
        geom.computeVertexNormals();
        const mat = new THREE.MeshStandardMaterial({ vertexColors:true, roughness:0.4, metalness:0.1, emissiveMap:null });
        const mesh = new THREE.Mesh(geom, mat);
        mesh.position.set(cx*CHUNK_SIZE, 0, cz*CHUNK_SIZE);
        mesh.castShadow = true;
        mesh.receiveShadow = true;
        return mesh;
    }

    function updateChunks() {
        const cx = Math.floor(player.x/CHUNK_SIZE);
        const cz = Math.floor(player.z/CHUNK_SIZE);
        for (let dx=-RENDER_DIST; dx<=RENDER_DIST; dx++) for (let dz=-RENDER_DIST; dz<=RENDER_DIST; dz++) {
            const key = `${cx+dx},${cz+dz}`;
            if (!chunkData.has(key)) {
                chunkData.set(key, generateChunk(cx+dx, cz+dz));
                const mesh = buildChunkMesh(cx+dx, cz+dz);
                if (mesh) { scene.add(mesh); chunkMeshes.set(key, mesh); }
            } else if (!chunkMeshes.has(key)) {
                const mesh = buildChunkMesh(cx+dx, cz+dz);
                if (mesh) { scene.add(mesh); chunkMeshes.set(key, mesh); }
            }
        }
        for (let [key, mesh] of chunkMeshes) {
            const [cxk, czk] = key.split(',').map(Number);
            if (Math.abs(cxk-cx) > RENDER_DIST+1 || Math.abs(czk-cz) > RENDER_DIST+1) {
                scene.remove(mesh); chunkMeshes.delete(key);
            }
        }
    }

    // --- Player & interaction (simplified but functional) ---
    function handleInput(delta) {
        const speed = keys.shift ? 8 : 4;
        let move = { x:0, z:0 };
        if (keys.w) move.z -= 1;
        if (keys.s) move.z += 1;
        if (keys.a) move.x -= 1;
        if (keys.d) move.x += 1;
        move.x *= speed*delta; move.z *= speed*delta;
        player.x += move.x; player.z += move.z;
        if (keys.space && player.onGround) { player.vY = 5; player.onGround = false; }
        player.vY -= 15*delta;
        player.y += player.vY*delta;
        if (player.y <= 10) { player.y = 10; player.vY = 0; player.onGround = true; }
    }

    // --- Block interaction with raycast ---
    let raycaster = new THREE.Raycaster();
    function handleBlockInteraction() {
        if (!mouseLocked) return;
        const dir = new THREE.Vector3(0,0,-1).applyQuaternion(camera.quaternion);
        raycaster.set(camera.position, dir);
        const intersects = raycaster.intersectObjects(Array.from(chunkMeshes.values()));
        if (intersects.length===0) return;
        const hit = intersects[0];
        const point = hit.point;
        const normal = hit.face.normal;
        let blockPos = {
            x: Math.floor(point.x - normal.x*0.5),
            y: Math.floor(point.y - normal.y*0.5),
            z: Math.floor(point.z - normal.z*0.5)
        };
        const cx = Math.floor(blockPos.x/CHUNK_SIZE);
        const cz = Math.floor(blockPos.z/CHUNK_SIZE);
        const lx = blockPos.x - cx*CHUNK_SIZE;
        const ly = blockPos.y;
        const lz = blockPos.z - cz*CHUNK_SIZE;
        if (ly<0 || ly>=CHUNK_SIZE) return;
        if (window.breakRequest) {
            const blocks = chunkData.get(`${cx},${cz}`);
            if (blocks) {
                const idx = ly*CHUNK_SIZE*CHUNK_SIZE + lz*CHUNK_SIZE + lx;
                const oldType = blocks[idx];
                if (oldType !== BLOCK_TYPES.AIR) {
                    if (oldType === BLOCK_TYPES.PROFIT) plt.profit = Math.min(100, plt.profit+2);
                    if (oldType === BLOCK_TYPES.LOVE) plt.love = Math.min(100, plt.love+2);
                    if (oldType === BLOCK_TYPES.TAX) plt.tax = Math.min(100, plt.tax+2);
                    blocks[idx] = BLOCK_TYPES.AIR;
                    rebuildChunkMesh(cx, cz);
                }
            }
            window.breakRequest = false;
        }
        if (window.placeRequest) {
            let placePos = {
                x: Math.floor(point.x + normal.x*0.5),
                y: Math.floor(point.y + normal.y*0.5),
                z: Math.floor(point.z + normal.z*0.5)
            };
            const pcx = Math.floor(placePos.x/CHUNK_SIZE);
            const pcz = Math.floor(placePos.z/CHUNK_SIZE);
            const plx = placePos.x - pcx*CHUNK_SIZE;
            const ply = placePos.y;
            const plz = placePos.z - pcz*CHUNK_SIZE;
            if (ply>=0 && ply<CHUNK_SIZE) {
                const blocks = chunkData.get(`${pcx},${pcz}`);
                if (blocks) {
                    const idx = ply*CHUNK_SIZE*CHUNK_SIZE + plz*CHUNK_SIZE + plx;
                    if (blocks[idx] === BLOCK_TYPES.AIR) {
                        let cost = 0;
                        if (selectedBlock === BLOCK_TYPES.PROFIT) cost = 5;
                        if (selectedBlock === BLOCK_TYPES.LOVE) cost = 5;
                        if (selectedBlock === BLOCK_TYPES.TAX) cost = 5;
                        if (cost===0 || (selectedBlock===BLOCK_TYPES.PROFIT && plt.profit>=cost) ||
                            (selectedBlock===BLOCK_TYPES.LOVE && plt.love>=cost) ||
                            (selectedBlock===BLOCK_TYPES.TAX && plt.tax>=cost)) {
                            if (cost>0) {
                                if (selectedBlock===BLOCK_TYPES.PROFIT) plt.profit -= cost;
                                if (selectedBlock===BLOCK_TYPES.LOVE) plt.love -= cost;
                                if (selectedBlock===BLOCK_TYPES.TAX) plt.tax -= cost;
                            }
                            blocks[idx] = selectedBlock;
                            rebuildChunkMesh(pcx, pcz);
                        }
                    }
                }
            }
            window.placeRequest = false;
        }
    }

    function rebuildChunkMesh(cx, cz) {
        const key = `${cx},${cz}`;
        const oldMesh = chunkMeshes.get(key);
        if (oldMesh) scene.remove(oldMesh);
        const newMesh = buildChunkMesh(cx, cz);
        if (newMesh) { scene.add(newMesh); chunkMeshes.set(key, newMesh); }
        else chunkMeshes.delete(key);
    }

    // --- Advanced graphics setup ---
    function setupGraphics() {
        scene = new THREE.Scene();
        scene.background = new THREE.Color(0x020218);
        scene.fog = new THREE.FogExp2(0x020218, 0.004);
        camera = new THREE.PerspectiveCamera(75, window.innerWidth/window.innerHeight, 0.1, 300);
        camera.position.set(0, 2, 5);
        renderer = new THREE.WebGLRenderer({ canvas:document.getElementById('canvas'), antialias:true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        renderer.shadowMap.type = THREE.PCFSoftShadowMap;
        renderer.toneMapping = THREE.ReinhardToneMapping;
        renderer.toneMappingExposure = 1.2;

        // Post-processing: bloom + RGB shift + afterimage (motion blur)
        const renderPass = new RenderPass(scene, camera);
        const bloomPass = new UnrealBloomPass(new THREE.Vector2(window.innerWidth, window.innerHeight), 1.0, 0.4, 0.85);
        rgbShiftPass = new ShaderPass(RGBShiftShader);
        rgbShiftPass.uniforms['amount'].value = 0.002;
        afterimagePass = new AfterimagePass(0.96);
        afterimagePass.renderToScreen = true;
        composer = new EffectComposer(renderer);
        composer.addPass(renderPass);
        composer.addPass(bloomPass);
        composer.addPass(rgbShiftPass);
        composer.addPass(afterimagePass);

        // Lighting
        ambientLight = new THREE.AmbientLight(0x404060, 0.5);
        scene.add(ambientLight);
        sunLight = new THREE.DirectionalLight(0xffdd99, 1.2);
        sunLight.position.set(5, 10, 3);
        sunLight.castShadow = true;
        sunLight.shadow.mapSize.width = 2048;
        sunLight.shadow.mapSize.height = 2048;
        sunLight.shadow.camera.near = 0.5;
        sunLight.shadow.camera.far = 60;
        sunLight.shadow.camera.left = -15;
        sunLight.shadow.camera.right = 15;
        sunLight.shadow.camera.top = 15;
        sunLight.shadow.camera.bottom = -15;
        scene.add(sunLight);
        fillLight = new THREE.PointLight(0xccaa88, 0.5);
        fillLight.position.set(0, 5, 0);
        scene.add(fillLight);

        // Dynamic water (reflective plane with waves)
        const waterGeo = new THREE.PlaneGeometry(200, 200);
        const waterMat = new THREE.MeshStandardMaterial({ color:0x3399ff, metalness:0.9, roughness:0.2, emissive:0x004466 });
        waterMesh = new THREE.Mesh(waterGeo, waterMat);
        waterMesh.rotation.x = -Math.PI/2;
        waterMesh.position.y = 0.1;
        waterMesh.receiveShadow = true;
        scene.add(waterMesh);

        // Skybox (simple starfield)
        const starTexture = (()=>{
            const canvas = document.createElement('canvas'); canvas.width=512; canvas.height=512;
            const ctx = canvas.getContext('2d'); ctx.fillStyle='black'; ctx.fillRect(0,0,512,512);
            for(let i=0;i<2000;i++){ ctx.fillStyle=`rgba(255,255,255,${Math.random()*0.8})`;
                ctx.fillRect(Math.random()*512, Math.random()*512, 1,1); }
            return new THREE.CanvasTexture(canvas);
        })();
        const skyMat = new THREE.MeshBasicMaterial({ map:starTexture, side:THREE.BackSide });
        skybox = new THREE.Mesh(new THREE.SphereGeometry(200, 32, 32), skyMat);
        scene.add(skybox);

        // Particles: dust, rain, snow, fireflies, leaves
        const particleCounts = { dust:2000, rain:0, snow:0, fireflies:500, leaves:300 };
        const particleGeom = new THREE.BufferGeometry();
        const particlePositions = new Float32Array(particleCounts.dust*3);
        for(let i=0;i<particleCounts.dust;i++) {
            particlePositions[i*3] = (Math.random()-0.5)*120;
            particlePositions[i*3+1] = Math.random()*20;
            particlePositions[i*3+2] = (Math.random()-0.5)*120;
        }
        particleGeom.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3));
        dustParticles = new THREE.Points(particleGeom, new THREE.PointsMaterial({ color:0xaa8866, size:0.05 }));
        scene.add(dustParticles);
        fireflyParticles = new THREE.Points(new THREE.BufferGeometry(), new THREE.PointsMaterial({ color:0xffaa66, size:0.08, blending:THREE.AdditiveBlending }));
        scene.add(fireflyParticles);

        // Instanced grass & flowers (simplified as many small cubes)
        const grassMat = new THREE.MeshStandardMaterial({ color:0x88aa44 });
        for(let i=0;i<4000;i++) {
            const x = (Math.random()-0.5)*100;
            const z = (Math.random()-0.5)*100;
