    // --- Main loop ---
    let prevTime = performance.now();
    function mainLoop() {
        const now = performance.now();
        let delta = Math.min(0.033, (now - prevTime)/1000);
        prevTime = now;

        handleInput(delta);
        handleBlockInteraction();
        updateChunks();
        updateDynamicGraphics(delta);
        updateSoulAuras();

        camera.position.x = player.x;
        camera.position.y = player.y + 1.6;
        camera.position.z = player.z;
        controls.target.set(player.x, player.y, player.z);
        controls.update();

        // Update stats UI
        document.getElementById('stats').innerHTML = `Souls:${souls.length} | PLT:${Math.floor(plt.profit)}/${Math.floor(plt.love)}/${Math.floor(plt.tax)}`;
        document.getElementById('timeIcon').innerHTML = timeOfDay<0.2||timeOfDay>0.8 ? '🌙 Night' : '🌞 Day';

        composer.render();
        requestAnimationFrame(mainLoop);
    }

    // --- Initialize everything ---
    function init() {
        setupGraphics();
        controls = new OrbitControls(camera, renderer.domElement);
        controls.enableZoom = false;
        controls.enablePan = false;
        controls.mouseButtons = { LEFT: THREE.MOUSE.ROTATE, RIGHT: THREE.MOUSE.PAN };

        // Event listeners
        window.addEventListener('keydown', e => {
            switch(e.code) {
                case 'KeyW': keys.w=1; break; case 'KeyS': keys.s=1; break;
                case 'KeyA': keys.a=1; break; case 'KeyD': keys.d=1; break;
                case 'Space': keys.space=1; e.preventDefault(); break;
                case 'ShiftLeft': keys.shift=1; break;
                case 'Digit1': selectedBlock=BLOCK_TYPES.GRASS; break;
                case 'Digit2': selectedBlock=BLOCK_TYPES.STONE; break;
                case 'Digit3': selectedBlock=BLOCK_TYPES.PROFIT; break;
                case 'Digit4': selectedBlock=BLOCK_TYPES.LOVE; break;
                case 'Digit5': selectedBlock=BLOCK_TYPES.TAX; break;
            }
        });
        window.addEventListener('keyup', e => {
            switch(e.code) {
                case 'KeyW': keys.w=0; break; case 'KeyS': keys.s=0; break;
                case 'KeyA': keys.a=0; break; case 'KeyD': keys.d=0; break;
                case 'Space': keys.space=0; break; case 'ShiftLeft': keys.shift=0; break;
            }
        });
        const canvas = document.getElementById('canvas');
        canvas.addEventListener('click', () => canvas.requestPointerLock());
        document.addEventListener('pointerlockchange', () => {
            mouseLocked = document.pointerLockElement === canvas;
            if(mouseLocked) document.body.addEventListener('mousemove', onMouseMove);
            else document.body.removeEventListener('mousemove', onMouseMove);
        });
        function onMouseMove(e) {
            if(!mouseLocked) return;
            const dx = e.movementX * 0.002;
            const dy = e.movementY * 0.002;
            camera.rotation.order = 'YXZ';
            camera.rotation.y -= dx;
            camera.rotation.x -= dy;
            if(camera.rotation.x > Math.PI/2) camera.rotation.x = Math.PI/2;
            if(camera.rotation.x < -Math.PI/2) camera.rotation.x = -Math.PI/2;
        }
        window.addEventListener('mousedown', e => {
            if(e.button===0) window.breakRequest = true;
            if(e.button===2) { window.placeRequest = true; e.preventDefault(); }
        });
        window.addEventListener('contextmenu', e => e.preventDefault());

        // Load souls from Soulverse (simulate)
        const saved = localStorage.getItem('soulforge_souls');
        if(saved) souls = JSON.parse(saved);
        else souls = [{ name:'Profit Prime', type:'profit' }];

        // Initial chunks
        updateChunks();

        mainLoop();
    }
    init();
