        waterMesh = new THREE.Mesh(waterGeo, waterMat);
        waterMesh.rotation.x = -Math.PI/2;
        waterMesh.position.y = 0.1;
        waterMesh.receiveShadow = true;
        scene.add(waterMesh);

        // Skybox (simple starfield)
        const starTexture = (()=>{
            const canvas = document.createElement('canvas'); canvas.width=512; canvas.height=512;
            const ctx = canvas.getContext('2d'); ctx.fillStyle='black'; ctx.fillRect(0,0,512,512);
            for(let i=0;i<2000;i++){ ctx.fillStyle=`rgba(255,255,255,${Math.random()*0.8})`;
                ctx.fillRect(Math.random()*512, Math.random()*512, 1,1); }
            return new THREE.CanvasTexture(canvas);
        })();
        const skyMat = new THREE.MeshBasicMaterial({ map:starTexture, side:THREE.BackSide });
        skybox = new THREE.Mesh(new THREE.SphereGeometry(200, 32, 32), skyMat);
        scene.add(skybox);

        // Particles: dust, rain, snow, fireflies, leaves
        const particleCounts = { dust:2000, rain:0, snow:0, fireflies:500, leaves:300 };
        const particleGeom = new THREE.BufferGeometry();
        const particlePositions = new Float32Array(particleCounts.dust*3);
        for(let i=0;i<particleCounts.dust;i++) {
            particlePositions[i*3] = (Math.random()-0.5)*120;
            particlePositions[i*3+1] = Math.random()*20;
            particlePositions[i*3+2] = (Math.random()-0.5)*120;
        }
        particleGeom.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3));
        dustParticles = new THREE.Points(particleGeom, new THREE.PointsMaterial({ color:0xaa8866, size:0.05 }));
        scene.add(dustParticles);
        fireflyParticles = new THREE.Points(new THREE.BufferGeometry(), new THREE.PointsMaterial({ color:0xffaa66, size:0.08, blending:THREE.AdditiveBlending }));
        scene.add(fireflyParticles);

        // Instanced grass & flowers (simplified as many small cubes)
        const grassMat = new THREE.MeshStandardMaterial({ color:0x88aa44 });
        for(let i=0;i<4000;i++) {
            const x = (Math.random()-0.5)*100;
            const z = (Math.random()-0.5)*100;
            const y = 10 + noise(x*0.2, 0, z*0.2)*3;
            if(y<20) {
                const grass = new THREE.Mesh(new THREE.BoxGeometry(0.1,0.3,0.1), grassMat);
                grass.position.set(x, y, z);
                grass.castShadow = true;
                scene.add(grass);
                grassInstances.push(grass);
            }
        }

        // Lens flare sprite
        const lensTex = (()=>{
            const c = document.createElement('canvas'); c.width=64; c.height=64;
            const ctx = c.getContext('2d'); ctx.fillStyle='rgba(255,200,100,0.8)';
            ctx.beginPath(); ctx.arc(32,32,28,0,2*Math.PI); ctx.fill();
            return new THREE.CanvasTexture(c);
        })();
        lensFlareSprite = new THREE.Sprite(new THREE.SpriteMaterial({ map:lensTex, blending:THREE.AdditiveBlending }));
        lensFlareSprite.scale.set(0.5,0.5,1);
        scene.add(lensFlareSprite);
    }

    // --- Day/Night, Weather, and Dynamic updates ---
    let lastTime = 0, timeAcc = 0;
    function updateDynamicGraphics(delta) {
        timeAcc += delta;
        // Day/night cycle
        timeOfDay += delta * 0.02;
        if(timeOfDay>1) timeOfDay-=1;
        const sunAngle = timeOfDay * Math.PI * 2;
        const sunX = Math.cos(sunAngle)*30;
        const sunY = Math.sin(sunAngle)*20;
        sunLight.position.set(sunX, sunY+5, 5);
        const intensity = Math.max(0.2, Math.sin(sunAngle)*0.8+0.4);
        sunLight.intensity = intensity;
        ambientLight.intensity = 0.3 + intensity*0.3;
        const skyHue = 0.55 - Math.sin(sunAngle)*0.1;
        scene.background.setHSL(skyHue, 0.8, 0.2 + intensity*0.3);
        skybox.material.color.setHSL(skyHue, 0.8, 0.1);

        // Lens flare toward sun
        const sunDir = new THREE.Vector3(sunX, sunY, 0).normalize();
        const camDir = camera.getWorldDirection(new THREE.Vector3());
        const dot = camDir.dot(sunDir);
        if(dot>0.8) lensFlareSprite.material.opacity = 0.8; else lensFlareSprite.material.opacity = 0;
        lensFlareSprite.position.copy(sunLight.position.clone().normalize().multiplyScalar(10));

        // Weather transitions
        if(Math.random()<0.0005) {
            weather = (weather==='sunny') ? 'rainy' : (weather==='rainy' ? 'snowy' : 'sunny');
            document.getElementById('weatherIcon').innerHTML = weather==='sunny'?'☀️ Sunny':(weather==='rainy'?'🌧️ Rainy':'❄️ Snowy');
        }
        if(weather==='rainy') {
            if(!rainParticles) {
                const rainGeo = new THREE.BufferGeometry();
                const count=3000;
                const pos = new Float32Array(count*3);
                for(let i=0;i<count;i++){ pos[i*3]=(Math.random()-0.5)*150; pos[i*3+1]=Math.random()*40; pos[i*3+2]=(Math.random()-0.5)*150; }
                rainGeo.setAttribute('position', new THREE.BufferAttribute(pos,3));
                rainParticles = new THREE.Points(rainGeo, new THREE.PointsMaterial({ color:0xaaddff, size:0.08 }));
                scene.add(rainParticles);
            }
            rainParticles.visible = true;
            if(snowParticles) snowParticles.visible = false;
        } else if(weather==='snowy') {
            if(!snowParticles) {
                const snowGeo = new THREE.BufferGeometry();
                const count=4000;
                const pos = new Float32Array(count*3);
                for(let i=0;i<count;i++){ pos[i*3]=(Math.random()-0.5)*150; pos[i*3+1]=Math.random()*40; pos[i*3+2]=(Math.random()-0.5)*150; }
                snowGeo.setAttribute('position', new THREE.BufferAttribute(pos,3));
                snowParticles = new THREE.Points(snowGeo, new THREE.PointsMaterial({ color:0xffffff, size:0.06 }));
                scene.add(snowParticles);
            }
            snowParticles.visible = true;
            if(rainParticles) rainParticles.visible = false;
        } else {
            if(rainParticles) rainParticles.visible = false;
            if(snowParticles) snowParticles.visible = false;
        }

        // Fireflies animation
        if(fireflyParticles.geometry.attributes.position) {
            const posAttr = fireflyParticles.geometry.attributes.position.array;
            for(let i=0;i<posAttr.length/3;i++) {
                posAttr[i*3] += (Math.random()-0.5)*0.08;
                posAttr[i*3+1] += (Math.random()-0.5)*0.04;
                posAttr[i*3+2] += (Math.random()-0.5)*0.08;
                if(Math.abs(posAttr[i*3])>70) posAttr[i*3] = (Math.random()-0.5)*70;
                if(posAttr[i*3+1]>25) posAttr[i*3+1] = 0;
                if(posAttr[i*3+1]<0) posAttr[i*3+1] = 25;
                if(Math.abs(posAttr[i*3+2])>70) posAttr[i*3+2] = (Math.random()-0.5)*70;
            }
            fireflyParticles.geometry.attributes.position.needsUpdate = true;
        }

        // Water wave effect
        if(waterMesh) waterMesh.position.y = 0.1 + Math.sin(timeAcc*2)*0.03;
    }

    // --- Soul-driven visuals (auras affect nearby particles) ---
