        document.getElementById('timeIcon').innerHTML = timeOfDay<0.2||timeOfDay>0.8 ? '🌙 Night' : '🌞 Day';

        composer.render();
        requestAnimationFrame(mainLoop);
    }

    // --- Initialize everything ---
    function init() {
        setupGraphics();
        controls = new OrbitControls(camera, renderer.domElement);
        controls.enableZoom = false;
        controls.enablePan = false;
        controls.mouseButtons = { LEFT: THREE.MOUSE.ROTATE, RIGHT: THREE.MOUSE.PAN };

        // Event listeners
        window.addEventListener('keydown', e => {
            switch(e.code) {
                case 'KeyW': keys.w=1; break; case 'KeyS': keys.s=1; break;
                case 'KeyA': keys.a=1; break; case 'KeyD': keys.d=1; break;
                case 'Space': keys.space=1; e.preventDefault(); break;
