                case 'KeyW': keys.w=0; break; case 'KeyS': keys.s=0; break;
                case 'KeyA': keys.a=0; break; case 'KeyD': keys.d=0; break;
                case 'Space': keys.space=0; break; case 'ShiftLeft': keys.shift=0; break;
            }
        });
        const canvas = document.getElementById('canvas');
        canvas.addEventListener('click', () => canvas.requestPointerLock());
        document.addEventListener('pointerlockchange', () => {
            mouseLocked = document.pointerLockElement === canvas;
            if(mouseLocked) document.body.addEventListener('mousemove', onMouseMove);
            else document.body.removeEventListener('mousemove', onMouseMove);
        });
        function onMouseMove(e) {
            if(!mouseLocked) return;
            const dx = e.movementX * 0.002;
            const dy = e.movementY * 0.002;
            camera.rotation.order = 'YXZ';
            camera.rotation.y -= dx;
            camera.rotation.x -= dy;
            if(camera.rotation.x > Math.PI/2) camera.rotation.x = Math.PI/2;
            if(camera.rotation.x < -Math.PI/2) camera.rotation.x = -Math.PI/2;
        }
