        const saved = localStorage.getItem('soulforge_souls');
        if(saved) souls = JSON.parse(saved);
        else souls = [{ name:'Profit Prime', type:'profit' }];

        // Initial chunks
        updateChunks();

        mainLoop();
    }
    init();
