    const CHUNK_SIZE = 16;
    const BLOCK_TYPES = { AIR:0, DIRT:1, GRASS:2, STONE:3, PROFIT:4, LOVE:5, TAX:6 };
    const BLOCK_COLORS = [0x000000, 0x8B5A2B, 0x7CB518, 0x808080, 0xffaa44, 0xff88aa, 0x88aaff];

    // --- Game state ---
    let scene, camera, renderer, composer, controls;
    let chunkData = new Map();
    let chunkMeshes = new Map();
    let player = { x:0, y:10, z:0, vY:0, onGround:true };
    let moveVec = { x:0, z:0 };
