    // --- Terrain generation (same as desktop, but simplified for speed) ---
    function getBlockType(wx, wy, wz) {
        const h = 10 + Math.sin(wx*0.1)*Math.cos(wz*0.1)*3 + Math.sin(wx*0.05)*1.5;
        if (wy > Math.floor(h)) return BLOCK_TYPES.AIR;
        const biome = Math.sin(wx*0.05)*Math.cos(wz*0.05);
        if (wy === Math.floor(h)) {
            if (biome > 0.3) return BLOCK_TYPES.PROFIT;
            else if (biome < -0.3) return BLOCK_TYPES.LOVE;
            else return BLOCK_TYPES.GRASS;
        }
        if (wy > h-3) return BLOCK_TYPES.DIRT;
        return BLOCK_TYPES.STONE;
    }

    function generateChunk(cx, cz) {
        const blocks = new Array(CHUNK_SIZE*CHUNK_SIZE*CHUNK_SIZE).fill(0);
        for (let x=0;x<CHUNK_SIZE;x++) for (let z=0;z<CHUNK_SIZE;z++) {
            const wx = cx*CHUNK_SIZE + x, wz = cz*CHUNK_SIZE + z;
            for (let y=0;y<CHUNK_SIZE;y++) {
                const type = getBlockType(wx, y, wz);
                if (type !== BLOCK_TYPES.AIR)
                    blocks[y*CHUNK_SIZE*CHUNK_SIZE + z*CHUNK_SIZE + x] = type;
            }
        }
        return blocks;
    }

    function buildChunkMesh(cx, cz) {
        const blocks = chunkData.get(`${cx},${cz}`);
        if (!blocks) return null;
        const geom = new THREE.BufferGeometry();
        const positions = [], colors = [], indices = [];
        const addCube = (x,y,z,type) => {
            const v = (a,b,c) => new THREE.Vector3(x+a, y+b, z+c);
            const col = new THREE.Color(BLOCK_COLORS[type]);
            const face = (a,b,c,d) => {
                const start = positions.length/3;
                [a,b,c,d].forEach(p => { positions.push(p.x,p.y,p.z); colors.push(col.r,col.g,col.b); });
                indices.push(start,start+1,start+2, start+2,start+3,start);
            };
            face(v(0,0,0), v(1,0,0), v(1,1,0), v(0,1,0));
            face(v(0,0,1), v(1,0,1), v(1,1,1), v(0,1,1));
            face(v(0,0,0), v(1,0,0), v(1,0,1), v(0,0,1));
            face(v(0,1,0), v(1,1,0), v(1,1,1), v(0,1,1));
            face(v(0,0,0), v(0,1,0), v(0,1,1), v(0,0,1));
            face(v(1,0,0), v(1,1,0), v(1,1,1), v(1,0,1));
        };
        for (let x=0;x<CHUNK_SIZE;x++) for (let z=0;z<CHUNK_SIZE;z++) for (let y=0;y<CHUNK_SIZE;y++) {
            const idx = y*CHUNK_SIZE*CHUNK_SIZE + z*CHUNK_SIZE + x;
            const type = blocks[idx];
            if (type !== BLOCK_TYPES.AIR) addCube(x, y, z, type);
        }
        geom.setAttribute('position', new THREE.BufferAttribute(new Float32Array(positions), 3));
        geom.setAttribute('color', new THREE.BufferAttribute(new Float32Array(colors), 3));
        geom.setIndex(indices);
        geom.computeVertexNormals();
        const mat = new THREE.MeshStandardMaterial({ vertexColors:true, roughness:0.5, metalness:0.1 });
        const mesh = new THREE.Mesh(geom, mat);
        mesh.position.set(cx*CHUNK_SIZE, 0, cz*CHUNK_SIZE);
        mesh.castShadow = true;
        mesh.receiveShadow = true;
        return mesh;
    }

    function updateChunks() {
        const cx = Math.floor(player.x/CHUNK_SIZE);
        const cz = Math.floor(player.z/CHUNK_SIZE);
        for (let dx=-RENDER_DIST; dx<=RENDER_DIST; dx++) for (let dz=-RENDER_DIST; dz<=RENDER_DIST; dz++) {
            const key = `${cx+dx},${cz+dz}`;
            if (!chunkData.has(key)) {
                chunkData.set(key, generateChunk(cx+dx, cz+dz));
                const mesh = buildChunkMesh(cx+dx, cz+dz);
                if (mesh) { scene.add(mesh); chunkMeshes.set(key, mesh); }
            } else if (!chunkMeshes.has(key)) {
                const mesh = buildChunkMesh(cx+dx, cz+dz);
                if (mesh) { scene.add(mesh); chunkMeshes.set(key, mesh); }
            }
        }
        for (let [key, mesh] of chunkMeshes) {
            const [cxk, czk] = key.split(',').map(Number);
            if (Math.abs(cxk-cx) > RENDER_DIST+1 || Math.abs(czk-cz) > RENDER_DIST+1) {
                scene.remove(mesh); chunkMeshes.delete(key);
            }
        }
    }

    function rebuildChunkMesh(cx, cz) {
        const key = `${cx},${cz}`;
        const old = chunkMeshes.get(key);
        if (old) scene.remove(old);
        const mesh = buildChunkMesh(cx, cz);
        if (mesh) { scene.add(mesh); chunkMeshes.set(key, mesh); }
        else chunkMeshes.delete(key);
    }

    // --- Player movement from touch joystick ---
    function updateMovement(delta) {
        const speed = isSprinting ? 6 : 3;
        player.x += moveVec.x * speed * delta;
        player.z += moveVec.z * speed * delta;
        // Gravity
        if (player.onGround && jumpRequested) {
            player.vY = 5;
            player.onGround = false;
            jumpRequested = false;
        }
        player.vY -= 15 * delta;
        player.y += player.vY * delta;
        if (player.y <= 10) {
            player.y = 10;
            player.vY = 0;
            player.onGround = true;
        }
    }

    // --- Block interaction with tap ---
    let raycaster = new THREE.Raycaster();
    let lastInteraction = 0;
    function handleBlockTap() {
        if (Date.now() - lastInteraction < 200) return;
        const dir = new THREE.Vector3(0,0,-1).applyQuaternion(camera.quaternion);
        raycaster.set(camera.position, dir);
        const intersects = raycaster.intersectObjects(Array.from(chunkMeshes.values()));
        if (intersects.length === 0) return;
        const hit = intersects[0];
        const point = hit.point;
        const normal = hit.face.normal;
        let blockPos = {
            x: Math.floor(point.x - normal.x*0.5),
            y: Math.floor(point.y - normal.y*0.5),
            z: Math.floor(point.z - normal.z*0.5)
        };
        const cx = Math.floor(blockPos.x/CHUNK_SIZE);
        const cz = Math.floor(blockPos.z/CHUNK_SIZE);
        const lx = blockPos.x - cx*CHUNK_SIZE;
        const ly = blockPos.y;
        const lz = blockPos.z - cz*CHUNK_SIZE;
        if (ly<0 || ly>=CHUNK_SIZE) return;
        const blocks = chunkData.get(`${cx},${cz}`);
        if (!blocks) return;
        const idx = ly*CHUNK_SIZE*CHUNK_SIZE + lz*CHUNK_SIZE + lx;
        if (breakMode) {
            const oldType = blocks[idx];
            if (oldType !== BLOCK_TYPES.AIR) {
                if (oldType === BLOCK_TYPES.PROFIT) plt.profit = Math.min(100, plt.profit+2);
                if (oldType === BLOCK_TYPES.LOVE) plt.love = Math.min(100, plt.love+2);
                if (oldType === BLOCK_TYPES.TAX) plt.tax = Math.min(100, plt.tax+2);
                blocks[idx] = BLOCK_TYPES.AIR;
                rebuildChunkMesh(cx, cz);
            }
        } else {
            let placePos = {
                x: Math.floor(point.x + normal.x*0.5),
                y: Math.floor(point.y + normal.y*0.5),
                z: Math.floor(point.z + normal.z*0.5)
            };
            const pcx = Math.floor(placePos.x/CHUNK_SIZE);
            const pcz = Math.floor(placePos.z/CHUNK_SIZE);
            const plx = placePos.x - pcx*CHUNK_SIZE;
            const ply = placePos.y;
            const plz = placePos.z - pcz*CHUNK_SIZE;
            if (ply>=0 && ply<CHUNK_SIZE) {
                const pblocks = chunkData.get(`${pcx},${pcz}`);
                if (pblocks) {
                    const pidx = ply*CHUNK_SIZE*CHUNK_SIZE + plz*CHUNK_SIZE + plx;
                    if (pblocks[pidx] === BLOCK_TYPES.AIR) {
                        let cost = 0;
                        if (selectedBlock === BLOCK_TYPES.PROFIT) cost = 5;
                        if (selectedBlock === BLOCK_TYPES.LOVE) cost = 5;
                        if (selectedBlock === BLOCK_TYPES.TAX) cost = 5;
                        if (cost===0 || (selectedBlock===BLOCK_TYPES.PROFIT && plt.profit>=cost) ||
                            (selectedBlock===BLOCK_TYPES.LOVE && plt.love>=cost) ||
                            (selectedBlock===BLOCK_TYPES.TAX && plt.tax>=cost)) {
                            if (cost>0) {
                                if (selectedBlock===BLOCK_TYPES.PROFIT) plt.profit -= cost;
                                if (selectedBlock===BLOCK_TYPES.LOVE) plt.love -= cost;
                                if (selectedBlock===BLOCK_TYPES.TAX) plt.tax -= cost;
                            }
                            pblocks[pidx] = selectedBlock;
                            rebuildChunkMesh(pcx, pcz);
                        }
                    }
                }
            }
        }
        lastInteraction = Date.now();
    }

    // --- Setup 3D scene (mobile-friendly) ---
    function initGraphics() {
        scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB);
        scene.fog = new THREE.FogExp2(0x87CEEB, 0.008);
        camera = new THREE.PerspectiveCamera(75, window.innerWidth/window.innerHeight, 0.1, 200);
        camera.position.set(0, 2, 5);
        renderer = new THREE.WebGLRenderer({ canvas:document.getElementById('gameCanvas'), antialias:true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        renderer.shadowMap.type = THREE.PCFSoftShadowMap;

        // No bloom on mobile for performance
        if (USE_BLOOM) {
            const renderPass = new RenderPass(scene, camera);
            const bloomPass = new UnrealBloomPass(new THREE.Vector2(window.innerWidth, window.innerHeight), 0.6, 0.3, 0.85);
            composer = new EffectComposer(renderer);
            composer.addPass(renderPass);
            composer.addPass(bloomPass);
        } else {
            composer = null;
        }

        // Lighting
        const ambient = new THREE.AmbientLight(0x404060, 0.6);
        scene.add(ambient);
        const sunLight = new THREE.DirectionalLight(0xffdd99, 1.0);
        sunLight.position.set(5, 10, 3);
        sunLight.castShadow = true;
        sunLight.shadow.mapSize.width = 512;
        sunLight.shadow.mapSize.height = 512;
        scene.add(sunLight);
        const fillLight = new THREE.PointLight(0xccaa88, 0.4);
        fillLight.position.set(0, 5, 0);
        scene.add(fillLight);

        // Simple ground water (optional, reduce complexity)
        const waterPlane = new THREE.Mesh(
            new THREE.PlaneGeometry(100, 100),
            new THREE.MeshStandardMaterial({ color:0x3399ff, metalness:0.7, roughness:0.3, transparent:true, opacity:0.6 })
        );
        waterPlane.rotation.x = -Math.PI/2;
        waterPlane.position.y = 0.05;
        waterPlane.receiveShadow = true;
        scene.add(waterPlane);

        // Minimal particles
        const particleGeo = new THREE.BufferGeometry();
        const positions = new Float32Array(PARTICLE_COUNT * 3);
        for(let i=0;i<PARTICLE_COUNT;i++) {
            positions[i*3] = (Math.random()-0.5)*80;
            positions[i*3+1] = Math.random()*15;
            positions[i*3+2] = (Math.random()-0.5)*80;
        }
        particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
        const particleMat = new THREE.PointsMaterial({ color:0x88aaff, size:0.08 });
        const particles = new THREE.Points(particleGeo, particleMat);
        scene.add(particles);

        // Simple grass (fewer instances)
        const grassMat = new THREE.MeshStandardMaterial({ color:0x88aa44 });
        for(let i=0;i<GRASS_COUNT;i++) {
            const x = (Math.random()-0.5)*80;
            const z = (Math.random()-0.5)*80;
            const y = 10 + Math.sin(x*0.2)*Math.cos(z*0.2)*3;
            if(y<20) {
                const grass = new THREE.Mesh(new THREE.BoxGeometry(0.1,0.3,0.1), grassMat);
                grass.position.set(x, y, z);
                grass.castShadow = true;
                scene.add(grass);
            }
        }
    }

    // --- Touch controls logic ---
    function setupTouchControls() {
        const joystickDiv = document.getElementById('joystickArea');
        const lookDiv = document.getElementById('lookArea');
        const joystickKnob = document.createElement('div');
        joystickKnob.style.width = '50px';
        joystickKnob.style.height = '50px';
        joystickKnob.style.borderRadius = '25px';
        joystickKnob.style.backgroundColor = '#ffaa66';
        joystickKnob.style.position = 'absolute';
        joystickKnob.style.left = '35px';
        joystickKnob.style.top = '35px';
        joystickKnob.style.opacity = '0.7';
        joystickDiv.appendChild(joystickKnob);

        joystickDiv.addEventListener('touchstart', (e) => {
            e.preventDefault();
            const rect = joystickDiv.getBoundingClientRect();
            const touch = e.touches[0];
            joystickActive = true;
            joystickCenter.x = rect.left + rect.width/2;
            joystickCenter.y = rect.top + rect.height/2;
            updateJoystick(touch.clientX, touch.clientY);
        });
        joystickDiv.addEventListener('touchmove', (e) => {
            e.preventDefault();
            const touch = e.touches[0];
            updateJoystick(touch.clientX, touch.clientY);
        });
        joystickDiv.addEventListener('touchend', (e) => {
            joystickActive = false;
            moveVec.x = 0;
            moveVec.z = 0;
            joystickKnob.style.left = '35px';
            joystickKnob.style.top = '35px';
        });

        function updateJoystick(clientX, clientY) {
            if (!joystickActive) return;
            let dx = clientX - joystickCenter.x;
            let dy = clientY - joystickCenter.y;
            const maxDist = 50;
            const dist = Math.min(maxDist, Math.hypot(dx, dy));
            const angle = Math.atan2(dy, dx);
            const limitedX = Math.cos(angle) * dist;
            const limitedY = Math.sin(angle) * dist;
            joystickKnob.style.left = (35 + limitedX) + 'px';
            joystickKnob.style.top = (35 + limitedY) + 'px';
            moveVec.x = limitedX / maxDist;
            moveVec.z = limitedY / maxDist;
        }

        lookDiv.addEventListener('touchstart', (e) => {
            e.preventDefault();
            lookActive = true;
            const touch = e.touches[0];
            lastTouchX = touch.clientX;
            lastTouchY = touch.clientY;
        });
        lookDiv.addEventListener('touchmove', (e) => {
            if (!lookActive) return;
            e.preventDefault();
            const touch = e.touches[0];
            const dx = touch.clientX - lastTouchX;
            const dy = touch.clientY - lastTouchY;
            if (dx !== 0 || dy !== 0) {
                cameraRotation.y -= dx * 0.005;
                cameraRotation.x -= dy * 0.005;
                cameraRotation.x = Math.max(-Math.PI/2, Math.min(Math.PI/2, cameraRotation.x));
                camera.rotation.order = 'YXZ';
                camera.rotation.y = cameraRotation.y;
                camera.rotation.x = cameraRotation.x;
                lastTouchX = touch.clientX;
                lastTouchY = touch.clientY;
            }
        });
        lookDiv.addEventListener('touchend', () => { lookActive = false; });
        lookDiv.addEventListener('touchcancel', () => { lookActive = false; });

        // Tap on canvas to break/place
        const canvas = document.getElementById('gameCanvas');
        canvas.addEventListener('touchstart', (e) => {
            e.preventDefault();
            handleBlockTap();
        });
    }

    // --- Buttons and UI ---
    let jumpRequested = false;
    function setupUI() {
        document.getElementById('jumpBtn').addEventListener('click', () => { jumpRequested = true; });
        document.getElementById('sprintBtn').addEventListener('click', () => { isSprinting = !isSprinting; document.getElementById('sprintBtn').style.background = isSprinting ? '#ffaa66' : '#2a2a3a'; });
        document.getElementById('breakBtn').addEventListener('click', () => { breakMode = true; document.getElementById('breakBtn').style.background = '#ffaa66'; document.getElementById('placeBtn').style.background = '#2a2a3a'; });
        document.getElementById('placeBtn').addEventListener('click', () => { breakMode = false; document.getElementById('placeBtn').style.background = '#ffaa66'; document.getElementById('breakBtn').style.background = '#2a2a3a'; });
        const blockOptions = document.querySelectorAll('.block-option');
        blockOptions.forEach(opt => {
            opt.addEventListener('click', () => {
                const blockId = parseInt(opt.dataset.block);
                selectedBlock = blockId;
                blockOptions.forEach(o => o.classList.remove('active'));
                opt.classList.add('active');
            });
        });
        blockOptions[0].classList.add('active');
    }

    // --- Animation loop ---
    let lastFrame = 0;
    function animate() {
        const now = performance.now();
        let delta = Math.min(0.033, (now - lastFrame) / 1000);
        lastFrame = now;

        updateMovement(delta);
        updateChunks();

        camera.position.x = player.x;
        camera.position.y = player.y + 1.6;
        camera.position.z = player.z;

        // Regenerate PLT slowly
        plt.profit = Math.min(100, plt.profit + 0.3 * delta);
        plt.love = Math.min(100, plt.love + 0.3 * delta);
        plt.tax = Math.min(100, plt.tax + 0.3 * delta);
        document.getElementById('stats').innerHTML = `💰${Math.floor(plt.profit)} ❤️${Math.floor(plt.love)} ⚖️${Math.floor(plt.tax)}`;

        if (composer) composer.render();
        else renderer.render(scene, camera);

        requestAnimationFrame(animate);
    }

    // --- Initialize ---
    function init() {
        initGraphics();
        setupTouchControls();
        setupUI();
        updateChunks();
        animate();
    }
    init();
</script>
</body>
</html>
```

---

📱 WHAT THIS MOBILE VERSION INCLUDES

Feature Implementation
Touch Joystick Left‑hand analog stick for movement – drag to move, release to stop.
Look Controls Drag anywhere on the right side of the screen to rotate camera.
Action Buttons Jump, Sprint, Break/Place mode toggles.
Block Selection Row of 5 block icons (grass, stone, profit gold, love pink, tax blue) at top right.
Performance Optimizations Reduced chunk render distance, fewer particles and grass, no bloom, lower shadow map resolution.
Mobile‑Friendly UI Buttons sized for touch, no keyboard/mouse required.
Same PLT Mechanics Break special blocks to gain resources; place them using resources.
Works Offline Single HTML file; runs locally.

---

🚀 HOW TO USE

1. Save the file as soulverse-mobile.html on your phone or tablet.
2. Open it in any modern browser (Chrome, Safari).
3. Use the on‑screen joystick to walk, drag on the right to look.
4. Tap the block icons to choose what to place.
5. Tap the BREAK button (hammer) to enter break mode, then tap blocks to destroy them.
6. Tap PLACE to return to placing mode.
7. Use JUMP to hop, SPRINT to run faster.

The world will generate infinite terrain with PLT biomes (profit gold, love pink, tax blue). Break special blocks to gain resources, and place them using those resources.

This mobile version is ready to build anywhere. 🌍
